// Image flag for display in match cards
function FlagImg({team, size=22}) {
  const code = TEAM_FLAGS[team];
  if (!code) return null;
  return (
    <img 
      src={"https://flagcdn.com/w40/" + code + ".png"} 
      alt={team}
      width={size}
      style={{height:"auto",borderRadius:2,verticalAlign:"middle",display:"inline-block"}}
      onError={function(e){e.target.style.display="none";}}
    />
  );
}

// Text flag for options/selects (uses country code as fallback text)
const flag = (t) => {
  const code = TEAM_FLAGS[t];
  return code ? "[" + code.toUpperCase() + "]" : "";
};

