const ALL_MATCHES = [...GROUP_MATCHES, ...KNOCKOUT_MATCHES];

// Lista oficial de los 48 equipos del Mundial 2026 (para selectores de Fase 2)
const ALL_TEAMS = [...new Set(GROUP_MATCHES.flatMap(m => [m.home, m.away]))].sort();

// Aplica el nombre real de equipo a un partido de Dieciseisavos si ya fue asignado por el admin.
// fase2Overrides: { R32_1: {home:"México", away:"Brasil"}, ... }
function applyFase2Override(match, fase2Overrides={}) {
  const ov = fase2Overrides[match.id];
  if (!ov) return match;
  return {...match, home: ov.home, away: ov.away, label: `${ov.home} vs ${ov.away}`};
}

// Today's date helper

const tomorrowStr = function() { var d = new Date(); d.setDate(d.getDate()+1); return d.toISOString().slice(0,10); };


// Is match open for predictions? Closes at 10PM Colombia the day before the match.
// Exception: matches on 2026-06-11 and 2026-06-12 close on 2026-06-11 at 11PM Colombia.
// openedDates: fechas que el admin forzó a ABIERTO manualmente (anula el cierre automático)
// blockedDates: fechas que el admin forzó a CERRADO manualmente (anula todo lo demás)
function isMatchOpen(match, blockedDates=[], openedDates=[]) {
  if (!match.date) return true;
  // Bloqueo manual tiene prioridad absoluta
  if (blockedDates.includes(match.date)) return false;
  // Apertura manual anula el cierre automático
  if (openedDates.includes(match.date)) return true;
  // Excepción jornada 1: partidos del 11 y 12 jun cierran el 11 jun a las 11PM
  if (match.date === "2026-06-11" || match.date === "2026-06-12") {
    return new Date() < new Date("2026-06-11T23:00:00-05:00");
  }
  const [y, mo, d] = match.date.split("-");
  const prevDay = new Date(parseInt(y), parseInt(mo)-1, parseInt(d)-1);
  const prevStr = prevDay.getFullYear() + "-" +
    String(prevDay.getMonth()+1).padStart(2,"0") + "-" +
    String(prevDay.getDate()).padStart(2,"0");
  const close = new Date(prevStr + "T22:00:00-05:00");
  return new Date() < close;
}

// Is match closed for Survivor (closes at kickoff time of the match)?
function isMatchClosed(closeTime, date) {
  if (!date || !closeTime) return false;
  const [h,m] = closeTime.split(":").map(Number);
  const close = new Date(`${date}T${String(h).padStart(2,"0")}:${String(m).padStart(2,"0")}:00-05:00`);
  return new Date() >= close;
}


// Is match visible today (show only today's + past matches)?
function isMatchVisible(match) {
  return match.date <= new Date(new Date().toLocaleString("en-US",{timeZone:"America/Bogota"})).toISOString().slice(0,10);
}

// Are predictions visible?
// Fase 1 (grupos): visible después del closeTime (hora de cierre de pronósticos)
// Fase 2+ (eliminatorias): visible solo después de la hora de inicio del partido
function arePredictionsVisible(match, blockedDates=[]) {
  // Si el admin bloqueó la fecha → pronósticos visibles para todos
  if (blockedDates.includes(match.date)) return true;
  if (match.fase >= 2) {
    // Fase 2+: ocultar hasta que empiece el partido
    const [h,m] = match.time.split(":").map(Number);
    const start = new Date(`${match.date}T${String(h).padStart(2,"0")}:${String(m).padStart(2,"0")}:00-05:00`);
    return new Date() >= start;
  }
  // Fase 1: visible después del closeTime automático
  if (!match.closeTime) return true;
  const [h,m] = match.closeTime.split(":").map(Number);
  const close = new Date(`${match.date}T${String(h).padStart(2,"0")}:${String(m).padStart(2,"0")}:00-05:00`);
  return new Date() >= close;
}

// ============================================================
// SCORING — Reglas actualizadas
// Fase 1 Grupos: 3pts marcador exacto + 1pt ganador/empate acertado
// Fase 2 Eliminatorias: 3pts marcador exacto (90min) + 1pt extra si empate y acierta ganador penales
// Fase 3 Campeón: 12/9/7/5 pts
// Tabla B Grupos: 2pts por 1° y 2° en orden exacto
// ============================================================
function calcMatchScore(matchId, pred, result) {
  if (!pred || !result) return 0;
  if (pred.homeGoals === "" || pred.awayGoals === "" || pred.homeGoals == null) return 0;
  const match = ALL_MATCHES.find(m=>m.id===matchId);
  if (!match) return 0;
  const ph = parseInt(pred.homeGoals), pa = parseInt(pred.awayGoals);
  const rh = parseInt(result.homeGoals), ra = parseInt(result.awayGoals);
  let pts = 0;

  const predResult = ph > pa ? "home" : ph < pa ? "away" : "draw";
  const realResult = rh > ra ? "home" : rh < ra ? "away" : "draw";

  if (match.fase === 1) {
    // Fase Grupos: solo UNA opción aplica (no acumulan)
    // 3pts: marcador exacto
    // 1pt: acertar ganador O pronosticar empate cuando hay empate (pero NO el marcador exacto)
    if (ph===rh && pa===ra) {
      pts = 3;
    } else if (predResult === realResult) {
      pts = 1;
    }
  } else {
    // Fase Eliminatorias: 3pts marcador exacto (90min) + 1pt ganador + 1pt extra empate+penales
    if (ph===rh && pa===ra) pts += 3;
    // 1pt por acertar ganador (incluso sin acertar marcador exacto)
    if (predResult === realResult) pts += 1;
    // +1 extra si pronosticó empate exacto Y acierta ganador en penales
    if (ph===pa && pa===ra && ph===rh && pred.penaltyWinner && result.penaltyWinner && pred.penaltyWinner===result.penaltyWinner) {
      pts += 1;
    }
  }
  return pts;
}

function calcGroupPickScore(pick, result) {
  if (!pick || !result) return 0;
  const exactFirst = pick.first && pick.first===result.first;
  const exactSecond = pick.second && pick.second===result.second;
  const wrongOrderFirst = pick.first && pick.first===result.second;
  const wrongOrderSecond = pick.second && pick.second===result.first;
  // 4pts: acertó 1° Y 2° en orden exacto
  if (exactFirst && exactSecond) return 4;
  // 2pts: acertó ambos pero en desorden
  if ((exactFirst || wrongOrderFirst) && (exactSecond || wrongOrderSecond)) return 2;
  // 1pt: acertó solo uno (en cualquier posición)
  if (exactFirst || exactSecond || wrongOrderFirst || wrongOrderSecond) return 1;
  return 0;
}

function calcFinalPickScore(picks, finalResults) {
  if (!picks || !finalResults) return 0;
  let pts = 0;
  if (picks.champion===finalResults.champion) pts+=12;
  if (picks.runnerUp===finalResults.runnerUp) pts+=9;
  if (picks.third===finalResults.third) pts+=7;
  if (picks.fourth===finalResults.fourth) pts+=5;
  return pts;
}

function getUserTotalScore(username, predictions, groupPicks, finalPicks, results, groupResults, finalResults) {
  let total = 0;
  for (const matchId in (predictions[username]||{})) {
    total += calcMatchScore(matchId, predictions[username][matchId], results[matchId]);
  }
  for (const group in (groupPicks[username]||{})) {
    total += calcGroupPickScore(groupPicks[username][group], groupResults[group]);
  }
  total += calcFinalPickScore(finalPicks[username], finalResults);
  return total;
}

// ============================================================
// LOCAL STORAGE PERSISTENCE (fallback offline)
// ============================================================
function useLocalState(key, init) {
  const [state, setStateRaw] = useState(() => {
    try { const v = localStorage.getItem(key); return v ? JSON.parse(v) : init; } catch { return init; }
  });
  const setState = useCallback(v => {
    setStateRaw(prev => {
      const next = typeof v==="function" ? v(prev) : v;
      try { localStorage.setItem(key, JSON.stringify(next)); } catch {}
      return next;
    });
  }, [key]);
  return [state, setState];
}

