// FASE 2 TAB
// ============================================================
function Fase2Tab({currentUser, predictions, results, savePrediction, blockedDates=[], openedDates=[], fase2Overrides={}}) {
  const [sub, setSub] = useState("dieciseisavos");
  const subPhases = [
    {key:"dieciseisavos", label:"Dieciseisavos"},
    {key:"octavos", label:"Octavos"},
    {key:"cuartos", label:"Cuartos de Final"},
    {key:"semis", label:"Semifinales"},
    {key:"tercer", label:"3er y 4to Puesto"},
    {key:"final", label:"Gran Final"},
  ];
  const matches = KNOCKOUT_MATCHES.filter(m => m.phase===sub)
    .map(m => applyFase2Override(m, fase2Overrides)); // Todos visibles siempre

  return (
    <div>
      <div className="phase-banner f2">⚡ Fase 2 · Eliminatorias — 3pts marcador · 1pt ganador · +1pt extra: empate exacto + acierta penales</div>
      <div className="phase-tabs">
        {subPhases.map(p=>(
          <button key={p.key} className={`phase-tab ${sub===p.key?"active":""}`} onClick={()=>setSub(p.key)}>{p.label}</button>
        ))}
      </div>
      {matches.length===0
        ? <div style={{textAlign:"center",padding:"40px 0",color:"#6B7A99"}}>
            <div style={{fontSize:36,marginBottom:8}}>⏳</div>
            <div>Esta fase aún no ha comenzado</div>
          </div>
        : <MatchList matches={matches} predictions={predictions} results={results}
            savePrediction={savePrediction} allPredictions={null} showScores={false} blockedDates={blockedDates} openedDates={openedDates} />
      }
    </div>
  );
}

// ============================================================
// FASE 3 TAB
// ============================================================
function Fase3Tab({currentUser, finalPicks, finalResults, saveFinalPick, fase3Blocked=false}) {
  const [local, setLocal] = useState(finalPicks);
  const [saved, setSaved] = useState(false);
  const fields=[{k:"champion",l:"🥇 Campeón",pts:12},{k:"runnerUp",l:"🥈 Subcampeón",pts:9},{k:"third",l:"🥉 Tercer Puesto",pts:7},{k:"fourth",l:"4️⃣ Cuarto Puesto",pts:5}];
  const [fase3Error, setFase3Error] = useState("");
  // Cierre Fase 3: 9 de junio 2026 a las 22:00 Colombia (UTC-5)
  const fase3Closed = fase3Blocked;
  function doSave(){
    if(!local.champion||!local.runnerUp||!local.third||!local.fourth){
      setFase3Error("⚠️ Debes seleccionar los 4 puestos antes de enviar.");
      setTimeout(()=>setFase3Error(""),3000); return;
    }
    if(new Set([local.champion,local.runnerUp,local.third,local.fourth]).size<4){
      setFase3Error("⚠️ No puedes repetir equipos en el podio.");
      setTimeout(()=>setFase3Error(""),3000); return;
    }
    saveFinalPick(local); setSaved(true); setTimeout(()=>setSaved(false),2500);
  }
  return (
    <div>
      <div className="phase-banner f3">🥇 Fase 3 · Pronósticos de Campeón — estos se ingresan al inicio del torneo y dan los puntos mayores</div>
      <div className="alert alert-warn">📅 Fecha límite: <strong>9 de junio de 2026, 10:00 PM</strong> hora Colombia. Solo puedes enviarlo una vez.</div>
      <div className="final-grid">
        {fields.map(f=>{
          const res = finalResults?.[f.k];
          return (
            <div key={f.k} className="final-pick">
              <div className="final-pick-label">{f.l}<span className="pts-badge">{f.pts} pts</span></div>
              {res && <div style={{fontSize:15,color:"#1B4F9E",marginBottom:6}}>Resultado: <FlagImg team={res} /> {res}</div>}
              <select value={local[f.k]||""} onChange={e=>setLocal(p=>({...p,[f.k]:e.target.value}))}
                disabled={!!finalPicks[f.k] || fase3Closed}
                style={{width:"100%",padding:10,background:"#F8F9FC",border:"1px solid var(--border)",borderRadius:8,color:"#1A1A2E",fontFamily:"inherit",fontSize:15,outline:"none"}}>
                <option value="">-- elige un equipo --</option>
                {TEAMS_LIST.map(t=><option key={t} value={t}>{flag(t)} {t}</option>)}
              </select>
            </div>
          );
        })}
      </div>
      {fase3Error && <div style={{color:"#C41E3A",fontWeight:700,fontSize:14,marginTop:8,textAlign:"center"}}>{fase3Error}</div>}
      {fase3Closed && !finalPicks.champion && (
        <div style={{marginTop:14,padding:"10px 16px",background:"rgba(196,30,58,0.08)",border:"1px solid #C41E3A",borderRadius:10,fontSize:14,color:"#C41E3A",fontWeight:700,textAlign:"center"}}>
          🔒 El plazo para enviar el pronóstico de campeón cerró el 9 de junio a las 10:00 PM.
        </div>
      )}
      {!fase3Closed && !finalPicks.champion && (
        <button className="btn-save" style={{marginTop:14}} onClick={doSave}>📨 Enviar pronósticos de campeón</button>
      )}
      {finalPicks.champion && <div style={{marginTop:14,fontSize:15,color:"#2D8A3E",fontWeight:700}}>✓ Pronósticos enviados y guardados</div>}
      {saved && <div style={{marginTop:8,fontSize:15,color:"#2D8A3E"}}>✓ ¡Guardado correctamente!</div>}
    </div>
  );
}

// ============================================================
// MATCH LIST — shared component
// ============================================================
function MatchList({matches, predictions, results, savePrediction, allPredictions, showScores, blockedDates=[], openedDates=[]}) {
  const [local, setLocal] = useState({});
  const [saved, setSaved] = useState({});
  const [confirming, setConfirming] = useState(null);
  const [inputError, setInputError] = useState({});

  function getPred(matchId){
    const saved = predictions[matchId] || {};
    const localPred = local[matchId] || {};
    // Fusionar: usar local si existe, sino usar el guardado de Supabase
    return {
      homeGoals: localPred.homeGoals !== undefined ? localPred.homeGoals : saved.homeGoals,
      awayGoals: localPred.awayGoals !== undefined ? localPred.awayGoals : saved.awayGoals,
      penaltyWinner: localPred.penaltyWinner !== undefined ? localPred.penaltyWinner : saved.penaltyWinner,
    };
  }

  function handleChange(matchId, field, value) {
    const clean = value.replace(/[^0-9]/g, "");
    // Mantener "" si está vacío, o número entero si tiene valor
    const num = clean === "" ? "" : Math.max(0, parseInt(clean, 10));
    setLocal(p=>({...p,[matchId]:{...getPred(matchId),[field]:num}}));
    setInputError(p=>({...p,[matchId]:""}));
  }

  function handleSave(matchId) {
    const p = getPred(matchId);
    if (p.homeGoals === "" || p.homeGoals == null || p.awayGoals === "" || p.awayGoals == null) {
      setInputError(prev=>({...prev,[matchId]:"⚠️ Debes ingresar el marcador de ambos equipos (puedes poner 0)."}));
      return;
    }
    setConfirming(matchId);
  }

  function confirmSave(matchId) {
    const p = getPred(matchId);
    savePrediction(matchId, p.homeGoals, p.awayGoals, p.penaltyWinner);
    setSaved(prev=>({...prev,[matchId]:true}));
    setConfirming(null);
    setTimeout(()=>setSaved(prev=>({...prev,[matchId]:false})),2000);
  }

  if (matches.length===0) return <div style={{color:"#6B7A99",textAlign:"center",padding:"30px 0"}}>No hay partidos disponibles aún.</div>;

  return (
    <div className="matches-grid">
      {matches.map(match=>{
        const pred = getPred(match.id);
        const result = results[match.id];
        const open = isMatchOpen(match, blockedDates, openedDates);
        const pred_saved = predictions[match.id]; const alreadySaved = !!(pred_saved && pred_saved.homeGoals != null && pred_saved.homeGoals !== '' && pred_saved.awayGoals != null && pred_saved.awayGoals !== '');
        const locked = !open || alreadySaved || !!result;
        const hasPred = pred.homeGoals!=null && pred.homeGoals!=="" && pred.awayGoals!=null && pred.awayGoals!=="";
        const isDraw = hasPred && parseInt(pred.homeGoals)===parseInt(pred.awayGoals);
        const isKO = match.fase===2;
        const myScore = result ? calcMatchScore(match.id, predictions[match.id], result) : null;

        return (
          <div key={match.id} className={`match-card ${hasPred?"predicted":""} ${locked&&!result&&!alreadySaved?"locked-card":""}`}>
            {/* Left info */}
            <div style={{minWidth:140,flexShrink:0}}>
              <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:16,color:"#1B4F9E",letterSpacing:1}}>{match.id}{match.group?` · Grupo ${match.group}`:""}</div>
              <div style={{fontSize:15,color:"#1A1A2E",fontWeight:600}}>📅 {fmtDate(match.date)}</div>
              <div style={{fontSize:14,color:"#6B7A99"}}>⏰ {match.time} col.</div>
              <div style={{fontSize:14,color:"#C41E3A"}}>🔒 Cierre: día anterior 10:00 PM Col.</div>
              {match.stadium && <div style={{fontSize:12,color:"#6B7A99",marginTop:2}}>🏟️ {match.stadium}</div>}
              {match.city && <div style={{fontSize:12,color:"#6B7A99"}}>📍 {match.city}{match.country?", "+match.country:""}</div>}
            </div>
            {/* Center: teams + score */}
            <div style={{flex:1}}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:10,marginBottom:8}}>
                <span className="team-name"><FlagImg team={match.home||""} /> {match.home||match.label}</span>
                <div style={{display:"flex",alignItems:"center",gap:5}}>
                  <input className="score-box" type="number" min="0" max="99"
                    value={pred.homeGoals??""} disabled={locked}
                    onKeyDown={e=>{if(["-","+","e","E","."].includes(e.key))e.preventDefault();}}
                    onChange={e=>!locked&&handleChange(match.id,"homeGoals",e.target.value)} />
                  <span className="score-sep">-</span>
                  <input className="score-box" type="number" min="0" max="99"
                    value={pred.awayGoals??""} disabled={locked}
                    onKeyDown={e=>{if(["-","+","e","E","."].includes(e.key))e.preventDefault();}}
                    onChange={e=>!locked&&handleChange(match.id,"awayGoals",e.target.value)} />
                </div>
                <span className="team-name away">{match.away||""} <FlagImg team={match.away||""} /></span>
              </div>
              {isKO && isDraw && !locked && (
                <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8,fontSize:15,color:"#6B7A99",marginBottom:6}}>
                  <span>Ganador en penales:</span>
                  <select value={pred.penaltyWinner||""} onChange={e=>handleChange(match.id,"penaltyWinner",e.target.value)}
                    style={{padding:"3px 8px",background:"#FFFFFF",border:"1px solid var(--border)",borderRadius:6,color:"#1A1A2E",fontFamily:"inherit",fontSize:15,outline:"none"}}>
                    <option value="">-- elige --</option>
                    <option value={match.home}>{match.home}</option>
                    <option value={match.away}>{match.away}</option>
                  </select>
                </div>
              )}
              {result && (
                <div style={{textAlign:"center",fontSize:15,color:"#1B4F9E",fontWeight:700}}>
                  ✅ Resultado: {result.homeGoals} - {result.awayGoals}
                  {result.penaltyWinner && <span style={{color:"#6B7A99",marginLeft:6}}>({result.penaltyWinner} pen.)</span>}
                  {myScore!==null && (
                    <span style={{marginLeft:10,color:myScore>0?"var(--green)":"var(--red)",fontFamily:"'Bebas Neue',cursive",fontSize:18}}>
                      {myScore>0?`+${myScore} pts ✓`:"✗ 0 pts"}
                    </span>
                  )}
                </div>
              )}
              <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8,marginTop:8,flexDirection:"column"}}>
                <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
                  {!locked && (
                    <button className="btn-save" onClick={()=>handleSave(match.id)}>
                      📨 Enviar
                    </button>
                  )}
                  {alreadySaved && !result && <span style={{fontSize:14,color:"#2D8A3E",fontWeight:700}}>✓ Enviado</span>}
                  {!open && !alreadySaved && !result && <span style={{fontSize:14,color:"#C41E3A",fontWeight:700}}>🔒 Cerrado</span>}
                  {saved[match.id] && <span style={{fontSize:14,color:"#2D8A3E",fontWeight:700}}>✓ ¡Guardado!</span>}
                </div>
                {inputError[match.id] && (
                  <div style={{fontSize:13,color:"#C41E3A",fontWeight:700,textAlign:"center",padding:"4px 10px",background:"rgba(196,30,58,0.08)",borderRadius:8}}>
                    {inputError[match.id]}
                  </div>
                )}
              </div>
              {/* Modal de confirmación */}
              {confirming===match.id && (
                <div style={{position:"fixed",top:0,left:0,width:"100%",height:"100%",background:"rgba(0,0,0,0.7)",zIndex:9999,display:"flex",alignItems:"center",justifyContent:"center"}}>
                  <div style={{background:"var(--card)",borderRadius:16,padding:28,maxWidth:340,width:"90%",textAlign:"center",border:"2px solid var(--blue)"}}>
                    <div style={{fontSize:28,marginBottom:8}}>⚠️</div>
                    <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"var(--blue)",marginBottom:8}}>¿Confirmas tu pronóstico?</div>
                    <div style={{fontSize:15,color:"var(--text)",marginBottom:6}}>{match.home} vs {match.away}</div>
                    <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:36,color:"var(--text)",marginBottom:6}}>
                      {getPred(match.id).homeGoals} — {getPred(match.id).awayGoals}
                    </div>
                    <div style={{fontSize:13,color:"var(--red)",fontWeight:700,marginBottom:16}}>⚠️ Una vez enviado NO podrás modificarlo</div>
                    <div style={{display:"flex",gap:10}}>
                      <button onClick={()=>setConfirming(null)} style={{flex:1,padding:"12px 0",borderRadius:8,border:"2px solid #1A1A2E",background:"transparent",color:"#1A1A2E",cursor:"pointer",fontFamily:"inherit",fontSize:16,fontWeight:700}}>
                        ✖ Cancelar
                      </button>
                      <button onClick={()=>confirmSave(match.id)} style={{flex:1,padding:"12px 0",borderRadius:8,border:"2px solid #2D8A3E",background:"#2D8A3E",color:"#fff",cursor:"pointer",fontFamily:"inherit",fontSize:16,fontWeight:700}}>
                        ✅ Confirmar
                      </button>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ============================================================
// GROUP PICKS SECTION
// ============================================================
function GroupPicksSection({groupPicks, groupResults, saveGroupPick, clasifBlocked=false}) {
  const [local, setLocal]=useState({});
  const [saved, setSaved]=useState({});
  const [errors, setErrors]=useState({});
  // Cierre clasificación grupos: 9 de junio 2026 a las 22:00 Colombia (UTC-5)
  const groupsClosed = clasifBlocked;
  function getPick(g){return local[g]||groupPicks[g]||{};}
  function handleSave(g){
    const p=getPick(g);
    if(!p.first||!p.second){
      setErrors(prev=>({...prev,[g]:"⚠️ Debes seleccionar el 1° y 2° lugar."}));
      setTimeout(()=>setErrors(prev=>({...prev,[g]:""})),3000); return;
    }
    if(p.first===p.second){
      setErrors(prev=>({...prev,[g]:"⚠️ El 1° y 2° no pueden ser el mismo equipo."}));
      setTimeout(()=>setErrors(prev=>({...prev,[g]:""})),3000); return;
    }
    saveGroupPick(g,p.first,p.second);
    setSaved(prev=>({...prev,[g]:true}));
    setTimeout(()=>setSaved(prev=>({...prev,[g]:false})),2000);
  }
  return (
    <div>
      <div className="alert alert-info">4pts: 1° y 2° exactos · 2pts: ambos en desorden · 1pt: solo uno acertado</div>
      <div className="groups-grid">
        {Object.entries(GROUPS).map(([g,teams])=>{
          const pick=getPick(g), res=groupResults[g];
          return (
            <div key={g} className="group-card">
              <div className="group-label">Grupo {g}</div>
              <div style={{fontSize:14,color:"#6B7A99",marginBottom:8}}>{teams.join(" · ")}</div>
              {res && <div style={{fontSize:15,color:"#1B4F9E",marginBottom:6}}>🏁 1°:<FlagImg team={res.first} /> {res.first} · 2°:<FlagImg team={res.second} /> {res.second}</div>}
              <div className="field" style={{marginBottom:8}}><label>1° Lugar</label>
                <select value={pick.first||""} disabled={!!groupPicks[g] || groupsClosed} onChange={e=>setLocal(p=>({...p,[g]:{...getPick(g),first:e.target.value}}))}>
                  <option value="">-- elige --</option>{teams.map(t=><option key={t} value={t}>{flag(t)} {t}</option>)}
                </select></div>
              <div className="field" style={{marginBottom:10}}><label>2° Lugar</label>
                <select value={pick.second||""} disabled={!!groupPicks[g] || groupsClosed} onChange={e=>setLocal(p=>({...p,[g]:{...getPick(g),second:e.target.value}}))}>
                  <option value="">-- elige --</option>{teams.map(t=><option key={t} value={t}>{flag(t)} {t}</option>)}
                </select></div>
              {errors[g] && <div style={{fontSize:13,color:"#C41E3A",fontWeight:700,marginBottom:4,textAlign:"center"}}>{errors[g]}</div>}
              {!groupPicks[g] && !groupsClosed && <button className="btn-save" style={{width:"100%"}} onClick={()=>handleSave(g)}>Guardar</button>}
              {!groupPicks[g] && groupsClosed && <div style={{fontSize:13,color:"#C41E3A",fontWeight:700,textAlign:"center"}}>🔒 Cerrado</div>}
              {groupPicks[g] && <div style={{fontSize:14,color:"#2D8A3E",fontWeight:700,textAlign:"center"}}>✓ Guardado</div>}
              {saved[g] && <div style={{fontSize:14,color:"#2D8A3E",textAlign:"center"}}>✓ ¡Guardado!</div>}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ============================================================
// RANKING TAB
// ============================================================
function RankingTab({leaderboard, currentUser, predictions, groupPicks, finalPicks, results, groupResults, finalResults, blockedDates=[], clasifBlocked=false, fase3Blocked=false}) {
  const [selected, setSelected] = React.useState(null);
  const [rankTab, setRankTab] = React.useState("fase1");
  const me = leaderboard.find(u=>u.username===currentUser.username);
  const myPos = leaderboard.indexOf(me)+1;

  if (selected) {
    const u = leaderboard.find(x=>x.username===selected);
    const preds = predictions[selected]||{};
    const gPicks = groupPicks[selected]||{};
    const fPicks = finalPicks[selected]||{};
    const fase1Matches = GROUP_MATCHES.filter(m => preds[m.id]);
    const fase2Matches = KNOCKOUT_MATCHES.filter(m => preds[m.id]);
    return (
      <div>
        <button onClick={()=>{setSelected(null);setRankTab("fase1");}} style={{marginBottom:14,padding:"7px 14px",borderRadius:8,border:"1px solid var(--border)",background:"transparent",color:"var(--text)",cursor:"pointer",fontFamily:"inherit",fontSize:14}}>
          ← Volver al ranking
        </button>
        <div style={{background:"var(--card)",borderRadius:12,padding:"14px 16px",marginBottom:14,border:"1px solid var(--border)",display:"flex",alignItems:"center",gap:12}}>
          <div className="avatar" style={{background:avatarColor(u.apodo||u.name),width:48,height:48,fontSize:20}}>{initials(u.apodo||u.name)}</div>
          <div>
            <div style={{fontWeight:900,fontSize:18}}>{u.apodo||u.name}</div>
            <div style={{fontSize:13,color:"var(--muted)"}}>@{u.username} · {u.tipo==="repollo"?"🥬 RePoLLo":"🆕 NueVón"}</div>
          </div>
          <div style={{marginLeft:"auto",fontFamily:"'Bebas Neue',cursive",fontSize:32,color:"var(--blue)"}}>{u.score}<span style={{fontSize:14,marginLeft:3}}>pts</span></div>
        </div>

        {/* Sub-pestañas */}
        <div style={{display:"flex",gap:6,marginBottom:14,flexWrap:"wrap"}}>
          {[{k:"fase1",l:"⚽ Fase 1"},{k:"clasif",l:"📊 Clasificación"},{k:"fase2",l:"⚡ Fase 2"},{k:"fase3",l:"🏆 Fase 3"}].map(t=>(
            <button key={t.k} onClick={()=>setRankTab(t.k)}
              style={{padding:"6px 12px",borderRadius:8,border:"2px solid",fontFamily:"inherit",fontSize:13,fontWeight:700,cursor:"pointer",
                background:rankTab===t.k?"#1B4F9E":"transparent",borderColor:rankTab===t.k?"#1B4F9E":"var(--border)",
                color:rankTab===t.k?"#fff":"var(--text)"}}>
              {t.l}
            </button>
          ))}
        </div>

        {/* ⚽ FASE 1 */}
        {rankTab==="fase1" && <>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:16,color:"var(--blue)",marginBottom:8}}>⚽ Partidos de Grupos</div>
          {fase1Matches.length===0 && <div style={{color:"var(--muted)",fontSize:14,marginBottom:12}}>Sin pronósticos</div>}
          {fase1Matches.map(m => {
            const pred=preds[m.id]; const res=results[m.id];
            const pts = pred&&res ? calcMatchScore(m.id,pred,res) : null;
            const visible = arePredictionsVisible(m, blockedDates);
            return (
              <div key={m.id} style={{background:"var(--card)",borderRadius:10,padding:"10px 14px",marginBottom:6,border:"1px solid var(--border)",display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
                <div style={{flex:1,minWidth:140}}>
                  <div style={{fontSize:13,fontWeight:700}}>{m.home} vs {m.away}</div>
                  <div style={{fontSize:12,color:"var(--muted)"}}>{m.date}</div>
                  {visible
                    ? <div style={{fontSize:13,color:"var(--blue)"}}>Pronóstico: {pred.homeGoals}-{pred.awayGoals}</div>
                    : <div style={{fontSize:12,color:"var(--muted)"}}>🔒 Pronóstico oculto hasta el cierre</div>}
                  {res && <div style={{fontSize:12,color:"var(--muted)"}}>Real: {res.homeGoals}-{res.awayGoals}</div>}
                </div>
                {pts!==null && <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:pts>0?"var(--green)":"#C41E3A"}}>{pts>0?`+${pts}`:0}pts</div>}
                {!res && <div style={{fontSize:12,color:"var(--muted)"}}>Pendiente</div>}
              </div>
            );
          })}
        </>}

        {/* 📊 CLASIFICACIÓN */}
        {rankTab==="clasif" && <>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:16,color:"var(--blue)",marginBottom:8}}>📊 Clasificación de Grupos</div>
          {Object.keys(gPicks).length===0 && <div style={{color:"var(--muted)",fontSize:14}}>Sin pronósticos</div>}
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:8}}>
            {Object.entries(gPicks).map(([group,pick])=>{
              const res=groupResults[group];
              let pts=0;
              if(res){
                if(pick.first===res.first&&pick.second===res.second) pts=4;
                else if((pick.first===res.second&&pick.second===res.first)) pts=2;
                else if(pick.first===res.first||pick.second===res.second||pick.first===res.second||pick.second===res.first) pts=1;
              }
              return (
                <div key={group} style={{background:"var(--card)",borderRadius:10,padding:"10px 12px",border:"1px solid var(--border)"}}>
                  <div style={{fontWeight:700,marginBottom:4}}>Grupo {group}</div>
                  {(res || clasifBlocked)
                    ? <><div style={{fontSize:13}}>1° {pick.first}</div><div style={{fontSize:13}}>2° {pick.second}</div></>
                    : <div style={{fontSize:12,color:"var(--muted)"}}>🔒 Oculto hasta cierre</div>}
                  {res && <><div style={{fontSize:12,color:"var(--muted)",marginTop:4}}>Real: {res.first} / {res.second}</div>
                  <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:20,color:pts>0?"var(--green)":"#C41E3A",marginTop:2}}>+{pts}pts</div></>}
                  {!res && <div style={{fontSize:12,color:"var(--muted)",marginTop:4}}>Pendiente</div>}
                </div>
              );
            })}
          </div>
        </>}

        {/* ⚡ FASE 2 */}
        {rankTab==="fase2" && <>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:16,color:"var(--blue)",marginBottom:8}}>⚡ Fase 2 — Eliminatorias</div>
          {fase2Matches.length===0 && <div style={{color:"var(--muted)",fontSize:14}}>Sin pronósticos</div>}
          {fase2Matches.map(m => {
            const pred=preds[m.id]; const res=results[m.id];
            const pts = pred&&res ? calcMatchScore(m.id,pred,res) : null;
            const visible = arePredictionsVisible(m, blockedDates);
            return (
              <div key={m.id} style={{background:"var(--card)",borderRadius:10,padding:"10px 14px",marginBottom:6,border:"1px solid var(--border)",display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
                <div style={{flex:1,minWidth:140}}>
                  <div style={{fontSize:13,fontWeight:700}}>{m.home} vs {m.away}</div>
                  <div style={{fontSize:12,color:"var(--muted)"}}>{m.date} · {m.phase}</div>
                  {visible
                    ? <div style={{fontSize:13,color:"var(--blue)"}}>Pronóstico: {pred.homeGoals}-{pred.awayGoals}</div>
                    : <div style={{fontSize:12,color:"var(--muted)"}}>🔒 Pronóstico oculto hasta el cierre</div>}
                  {res && <div style={{fontSize:12,color:"var(--muted)"}}>Real: {res.homeGoals}-{res.awayGoals}</div>}
                </div>
                {pts!==null && <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:pts>0?"var(--green)":"#C41E3A"}}>{pts>0?`+${pts}`:0}pts</div>}
                {!res && <div style={{fontSize:12,color:"var(--muted)"}}>Pendiente</div>}
              </div>
            );
          })}
        </>}

        {/* 🏆 FASE 3 */}
        {rankTab==="fase3" && <>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:16,color:"var(--blue)",marginBottom:8}}>🏆 Pronóstico Final</div>
          {!fPicks.champion && <div style={{color:"var(--muted)",fontSize:14}}>Sin pronósticos</div>}
          {fPicks.champion && (
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(150px,1fr))",gap:8}}>
              {[["🥇 Campeón","champion",12],["🥈 Subcampeón","runnerUp",9],["🥉 3er Puesto","third",7],["4° Lugar","fourth",5]].map(([label,key,maxPts])=>{
                const acerto=finalResults?.[key]&&fPicks[key]===finalResults[key];
                return (
                  <div key={key} style={{background:"var(--card)",borderRadius:10,padding:"10px 12px",border:`1px solid ${acerto?"var(--green)":"var(--border)"}`}}>
                    <div style={{fontSize:12,color:"var(--muted)",fontWeight:700}}>{label}</div>
                    {(finalResults?.[key] || fase3Blocked)
                      ? <div style={{fontSize:14,fontWeight:700,marginTop:2}}>{fPicks[key]||"—"}</div>
                      : <div style={{fontSize:12,color:"var(--muted)",marginTop:2}}>🔒 Oculto hasta el cierre</div>}
                    {finalResults?.[key] && <div style={{fontSize:12,color:"var(--muted)"}}>Real: {finalResults[key]}</div>}
                    <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:20,color:acerto?"var(--green)":"#C41E3A",marginTop:4}}>{acerto?`+${maxPts}`:0}pts</div>
                  </div>
                );
              })}
            </div>
          )}
        </>}
      </div>
    );
  }

  return (
    <div>
      {!currentUser.isAdmin && me && (
        <div className="stats-row">
          <div className="stat-card"><div className="stat-val">{myPos}°</div><div className="stat-label">Tu posición</div></div>
          <div className="stat-card"><div className="stat-val">{me.score}</div><div className="stat-label">Tus puntos</div></div>
          <div className="stat-card"><div className="stat-val">{leaderboard.length}</div><div className="stat-label">Participantes</div></div>
        </div>
      )}
      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {leaderboard.map((u,i)=>(
          <div key={u.username} className="lb-row" style={{cursor:"pointer",...(u.username===currentUser.username?{borderColor:"#1B4F9E"}:{})}}
            onClick={()=>setSelected(u.username)}>
            <div className={`lb-pos ${i===0?"p1":i===1?"p2":i===2?"p3":""}`}>{i+1}</div>
            <div className="avatar" style={{background:avatarColor(u.apodo||u.name)}}>{initials(u.apodo||u.name)}</div>
            <div style={{flex:1,fontWeight:600,fontSize:16}}>{u.apodo||u.name}{u.username===currentUser.username&&<span style={{fontSize:14,color:"#1B4F9E",marginLeft:6}}>← Tú</span>}</div>
            <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:28,color:"#1B4F9E"}}>{u.score}<span style={{fontSize:14,color:"#6B7A99",fontFamily:"inherit",marginLeft:3}}>pts</span></div>
            <div style={{fontSize:12,color:"var(--muted)"}}>›</div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ============================================================
// VER PRONÓSTICOS TAB — partido-centric, solo visible tras cierre
// ============================================================
function VerPronosticosTab({currentUser, users, predictions, results, groupPicks, finalPicks, groupResults, finalResults, blockedDates=[], fase2Overrides={}}) {
  const [freshPreds, setFreshPreds] = useState({});
  const [phase, setPhase]=useState("grupos");
  const [selectedMatch, setSelectedMatch]=useState(null);
  const [fechaFiltroVer, setFechaFiltroVer]=useState("");
  const participants=users.filter(u=>!u.isAdmin && !u.isDemo);
  const subPhases=[
    {key:"grupos",label:"Grupos",fase:1},
    {key:"dieciseisavos",label:"Dieciseisavos",fase:2},
    {key:"octavos",label:"Octavos",fase:2},
    {key:"cuartos",label:"Cuartos",fase:2},
    {key:"semis",label:"Semis",fase:2},
    {key:"tercer",label:"3er Puesto",fase:2},
    {key:"final",label:"Final",fase:2},
  ];

  function exportarExcel() {
    const rows = [];
    // Encabezado
    rows.push(["Jugador","Apodo","Fase","Partido","Fecha","Pronóstico Local","Pronóstico Visitante","Penales (pronóstico)","Resultado Local","Resultado Visitante","¿Acertó marcador?","¿Acertó ganador?","Puntos"]);

    // Partidos
    participants.forEach(u => {
      const preds = predictions[u.username] || {};
      ALL_MATCHES.forEach(m => {
        const pred = preds[m.id];
        if (!pred) return;
        const res = results[m.id];
        // Jugadores: solo exportar si el partido ya cerró (pronóstico visible)
        if (!currentUser.isAdmin && !arePredictionsVisible(m, blockedDates)) return;
        let acertoMarcador = "", acertoGanador = "", pts = "";
        if (res) {
          acertoMarcador = (pred.homeGoals===res.homeGoals && pred.awayGoals===res.awayGoals) ? "SÍ" : "NO";
          const predGanador = pred.homeGoals>pred.awayGoals?"local":pred.homeGoals<pred.awayGoals?"visitante":"empate";
          const resGanador = res.homeGoals>res.awayGoals?"local":res.homeGoals<res.awayGoals?"visitante":"empate";
          acertoGanador = predGanador===resGanador ? "SÍ" : "NO";
          pts = calcMatchScore(m.id, pred, res);
        }
        rows.push([
          u.name, u.apodo||u.name, m.fase===1?"Grupos":"Eliminatorias",
          `${m.home} vs ${m.away}`, m.date,
          pred.homeGoals, pred.awayGoals, pred.penaltyWinner||"",
          res?res.homeGoals:"", res?res.awayGoals:"",
          acertoMarcador, acertoGanador, pts
        ]);
      });
    });

    // Tabla B
    rows.push([]);
    rows.push(["TABLA B — CLASIFICACIÓN DE GRUPOS"]);
    rows.push(["Jugador","Apodo","Grupo","1° Pronosticado","2° Pronosticado","1° Real","2° Real","Puntos"]);
    participants.forEach(u => {
      const picks = groupPicks[u.username] || {};
      Object.entries(picks).forEach(([group, pick]) => {
        const res = groupResults[group];
        let pts = "";
        if (res) {
          if (pick.first===res.first && pick.second===res.second) pts=4;
          else if (pick.first===res.second && pick.second===res.first) pts=2;
          else if ([pick.first,pick.second].includes(res.first) || [pick.first,pick.second].includes(res.second)) pts=1;
          else pts=0;
        }
        rows.push([u.name, u.apodo||u.name, `Grupo ${group}`, pick.first, pick.second, res?res.first:"", res?res.second:"", pts]);
      });
    });

    // Fase 3
    rows.push([]);
    rows.push(["FASE 3 — PODIO FINAL"]);
    rows.push(["Jugador","Apodo","Campeón","Subcampeón","3er Puesto","4° Lugar","Puntos"]);
    participants.forEach(u => {
      const fp = finalPicks[u.username];
      if (!fp || !fp.champion) return;
      rows.push([u.name, u.apodo||u.name, fp.champion, fp.runnerUp||"", fp.third||"", fp.fourth||"", ""]);
    });

    // Convertir a CSV
    const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g,'""')}"`).join(",")).join("\n");
    const blob = new Blob(["\uFEFF"+csv], {type:"text/csv;charset=utf-8;"});
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `RePoLLa_Pronosticos_${new Date(new Date().toLocaleString("en-US",{timeZone:"America/Bogota"})).toISOString().slice(0,10)}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  }
  const matches = ALL_MATCHES.filter(m=>m.phase===phase)
    .filter(m => phase!=="grupos" || !fechaFiltroVer || m.date===fechaFiltroVer)
    .map(m => applyFase2Override(m, fase2Overrides))
    .sort((a,b) => {
      // Ordenar cronológicamente por fecha y hora
      const da = a.date + "T" + (a.time||"00:00");
      const db = b.date + "T" + (b.time||"00:00");
      return da.localeCompare(db);
    });

  function getScore(matchId, username) {
    // Usar freshPreds si están disponibles (datos frescos de Supabase para este partido)
    const pred = (freshPreds && freshPreds[username]) 
      ? freshPreds[username]
      : predictions[username]?.[matchId];
    const result=results[matchId];
    if (!pred||!result) return null;
    if (pred.homeGoals===null || pred.homeGoals===undefined || pred.homeGoals==="") return null;
    return calcMatchScore(matchId, pred, result);
  }

  const activeMatch = selectedMatch ? ALL_MATCHES.find(m=>m.id===selectedMatch) : null;

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12,flexWrap:"wrap"}}>
        <div className="alert alert-info" style={{margin:0,flex:1}}>
          🔒 Los pronósticos solo son visibles <strong>después del cierre</strong> de cada partido.
        </div>
        <button onClick={exportarExcel} style={{padding:"7px 12px",borderRadius:8,border:"1px solid var(--green)",fontFamily:"inherit",fontSize:14,fontWeight:700,cursor:"pointer",background:"rgba(45,138,62,0.1)",color:"var(--green)"}}>
          📊 Exportar Excel
        </button>

      </div>
      <div className="phase-tabs">
        {subPhases.map(p=>(
          <button key={p.key} className={`phase-tab ${phase===p.key?"active":""}`}
            onClick={()=>{setPhase(p.key);setSelectedMatch(null);setFechaFiltroVer("");}}>{p.label}</button>
        ))}
      </div>

      {phase==="grupos" && (
        <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:12}}>
          <button onClick={()=>setFechaFiltroVer("")} style={{padding:"6px 12px",borderRadius:8,border:"1px solid",fontSize:13,fontWeight:700,cursor:"pointer",
            background:fechaFiltroVer===""?"#1B4F9E":"transparent",borderColor:fechaFiltroVer===""?"#1B4F9E":"var(--border)",
            color:fechaFiltroVer===""?"#fff":"var(--text)"}}>Todas</button>
          {[...new Set(GROUP_MATCHES.map(m=>m.date))].sort().map(f=>(
            <button key={f} onClick={()=>setFechaFiltroVer(f)} style={{padding:"6px 12px",borderRadius:8,border:"1px solid",fontSize:13,fontWeight:700,cursor:"pointer",
              background:fechaFiltroVer===f?"#1B4F9E":"transparent",borderColor:fechaFiltroVer===f?"#1B4F9E":"var(--border)",
              color:fechaFiltroVer===f?"#fff":"var(--text)"}}>{f.slice(5)}</button>
          ))}
        </div>
      )}

      {!selectedMatch && (
        <div className="matches-grid">
          {matches.map(match=>{
            const result=results[match.id];
            const visible=arePredictionsVisible(match, blockedDates);
            const count=participants.filter(u=>predictions[u.username]?.[match.id]?.homeGoals!=null&&predictions[u.username]?.[match.id]?.homeGoals!=="").length;
            const correct=participants.filter(u=>getScore(match.id,u.username)>0).length;
            return (
              <div key={match.id} className="match-card" style={{cursor:"pointer"}} onClick={async()=>{
                  if (!visible) return;
                  setSelectedMatch(match.id);
                  // Cargar pronósticos frescos de Supabase para este partido
                  const {data: fp} = await sb.from("predictions").select("username,home_goals,away_goals,penalty_winner").eq("match_id", match.id);
                  if (fp) {
                    const m = {};
                    fp.forEach(p => { m[p.username] = {homeGoals: p.home_goals !== null ? Number(p.home_goals) : null, awayGoals: p.away_goals !== null ? Number(p.away_goals) : null, penaltyWinner: p.penalty_winner}; });
                    setFreshPreds(m);
                  }
                }}>
                <div style={{minWidth:120,flexShrink:0}}>
                  <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:16,color:"#1B4F9E"}}>{match.id}</div>
                  <div style={{fontSize:14,color:"#6B7A99"}}>{fmtDate(match.date)} · {match.time}</div>
                  {match.stadium&&<div style={{fontSize:12,color:"#6B7A99"}}>🏟️ {match.stadium}</div>}
                </div>
                <div style={{flex:1,textAlign:"center"}}>
                  <div style={{fontWeight:700,fontSize:15,marginBottom:4}}><FlagImg team={match.home} /> {match.home} <span style={{color:"#6B7A99"}}>vs</span> {match.away} <FlagImg team={match.away} /></div>
                  {result ? <div style={{fontSize:15,color:"#1B4F9E",fontWeight:700}}>✅ {result.homeGoals}-{result.awayGoals} · {correct}/{count} acertaron</div>
                    : visible ? <div style={{fontSize:14,color:"#6B7A99"}}>{count} pronóstico{count!==1?"s":""} · haz clic para ver</div>
                    : <div style={{fontSize:14,color:"#C41E3A"}}>🔒 Pronósticos ocultos hasta el cierre</div>}
                </div>
                {visible && <div style={{fontSize:15,color:"#1B4F9E",fontWeight:600}}>Ver →</div>}
              </div>
            );
          })}
        </div>
      )}

      {selectedMatch && activeMatch && (
        <div>
          <button onClick={()=>setSelectedMatch(null)} style={{background:"transparent",border:"1px solid var(--border)",color:"#6B7A99",padding:"5px 12px",borderRadius:8,fontFamily:"inherit",fontSize:15,cursor:"pointer",marginBottom:14}}>
            ← Volver
          </button>
          <div className="card" style={{marginBottom:14}}>
            <div className="card-body">
              <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:16,flexWrap:"wrap"}}>
                <div style={{textAlign:"right",flex:1}}>
                  <div style={{fontSize:30}}><FlagImg team={activeMatch.home} size={36} /></div>
                  <div style={{fontWeight:700,fontSize:17}}>{activeMatch.home}</div>
                </div>
                <div style={{textAlign:"center"}}>
                  <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:15,color:"#1B4F9E"}}>{activeMatch.id} · {fmtDate(activeMatch.date)}</div>
                  <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:28,color:"#6B7A99"}}>VS</div>
                  {results[activeMatch.id] && (
                    <div style={{padding:"4px 14px",background:"#F8F9FC",borderRadius:8,border:"1px solid var(--gold)"}}>
                      <div style={{fontSize:12,color:"#6B7A99"}}>Resultado oficial</div>
                      <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:32,color:"#1B4F9E"}}>{results[activeMatch.id].homeGoals} - {results[activeMatch.id].awayGoals}</div>
                    </div>
                  )}
                </div>
                <div style={{textAlign:"left",flex:1}}>
                  <div style={{fontSize:30}}><FlagImg team={activeMatch.away} size={36} /></div>
                  <div style={{fontWeight:700,fontSize:17}}>{activeMatch.away}</div>
                </div>
              </div>
            </div>
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:8}}>
            {participants.map(u=>{
              const pred=freshPreds[u.username] ?? predictions[u.username]?.[activeMatch.id];
              const pts=getScore(activeMatch.id, u.username);
              const res=results[activeMatch.id];
              return (
                <div key={u.username} style={{display:"flex",alignItems:"center",gap:14,padding:"12px 16px",background:"#F8F9FC",borderRadius:12,
                  border:`1px solid ${pts===null?"var(--border)":pts>0?"var(--green)":res?"var(--red)":"var(--border)"}`}}>
                  <div className="avatar" style={{background:avatarColor(u.apodo||u.name),width:36,height:36,fontSize:15}}>{initials(u.apodo||u.name)}</div>
                  <div style={{flex:1,fontWeight:600,fontSize:15}}>{u.apodo||u.name}</div>
                  <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:28,color:pts===null?"#1B4F9E":pts>0?"var(--green)":res?"var(--red)":"#1B4F9E"}}>
                    {pred?`${pred.homeGoals} - ${pred.awayGoals}`:<span style={{color:"#B0B8CC",fontSize:15,fontStyle:"italic"}}>Sin pronóstico</span>}
                  </div>
                  <div style={{minWidth:54,textAlign:"right"}}>
                    {pts!==null && <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:24,color:pts>0?"var(--green)":"var(--red)"}}>{pts>0?`+${pts}`:0}<span style={{fontSize:13}}> pts</span></div>}
                    {!res && pred && <div style={{fontSize:12,color:"#6B7A99"}}>Enviado</div>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* TABLA B — Clasificación de grupos */}
      {!selectedMatch && phase==="grupos" && groupPicks && (
        <div style={{marginTop:20}}>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:20,color:"var(--blue)",marginBottom:10}}>📊 Pronósticos Tabla B — Clasificación de Grupos</div>
          {participants.map(u => {
            const picks = groupPicks[u.username];
            if (!picks || Object.keys(picks).length===0) return null;
            return (
              <div key={u.username} style={{background:"var(--card)",borderRadius:10,padding:"10px 14px",marginBottom:8,border:"1px solid var(--border)"}}>
                <div style={{fontWeight:700,fontSize:14,marginBottom:6}}>{u.apodo||u.name}</div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:6}}>
                  {Object.entries(picks).map(([group,pick]) => (
                    <div key={group} style={{fontSize:13,background:"rgba(27,79,158,0.06)",borderRadius:8,padding:"4px 8px"}}>
                      <span style={{fontWeight:700}}>Grupo {group}:</span> 1°{pick.first} / 2°{pick.second}
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* FASE 3 — Campeón */}
      {!selectedMatch && phase==="grupos" && finalPicks && (
        <div style={{marginTop:20}}>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:20,color:"var(--blue)",marginBottom:10}}>🏆 Pronósticos Fase 3 — Campeón</div>
          {participants.map(u => {
            const fp = finalPicks[u.username];
            if (!fp || !fp.champion) return null;
            return (
              <div key={u.username} style={{background:"var(--card)",borderRadius:10,padding:"10px 14px",marginBottom:8,border:"1px solid var(--border)"}}>
                <div style={{fontWeight:700,fontSize:14,marginBottom:4}}>{u.apodo||u.name}</div>
                <div style={{fontSize:13,display:"flex",gap:12,flexWrap:"wrap"}}>
                  <span>🥇 {fp.champion}</span>
                  <span>🥈 {fp.runnerUp}</span>
                  <span>🥉 {fp.third}</span>
                  <span>4° {fp.fourth}</span>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// MIS PUNTOS TAB
// ============================================================
function MisPuntosTab({currentUser, predictions, groupPicks, finalPicks, results, groupResults, finalResults}) {
  let matchPts=0, groupPts=0, finalPts=0;
  const matchRows=[], groupRows=[], finalRows=[];

  for (const matchId in predictions) {
    const pred=predictions[matchId], result=results[matchId];
    if (!result) continue;
    const pts=calcMatchScore(matchId, pred, result);
    const match=ALL_MATCHES.find(m=>m.id===matchId);
    matchRows.push({matchId, match, pred, result, pts});
    matchPts+=pts;
  }
  for (const group in groupPicks) {
    const pick=groupPicks[group], res=groupResults[group];
    if (!res) continue;
    const pts=calcGroupPickScore(pick,res);
    groupRows.push({group,pick,res,pts});
    groupPts+=pts;
  }
  if (finalPicks && finalResults) {
    const fp = finalPicks;
    [{k:"champion",l:"Campeón",v:12},{k:"runnerUp",l:"Subcampeón",v:9},{k:"third",l:"Tercer Puesto",v:7},{k:"fourth",l:"Cuarto Puesto",v:5}].forEach(f=>{
      if (fp[f.k] && finalResults[f.k]) {
        const pts=fp[f.k]===finalResults[f.k]?f.v:0;
        finalRows.push({label:f.l,pick:fp[f.k],result:finalResults[f.k],pts,max:f.v});
        finalPts+=pts;
      }
    });
  }

  const total=matchPts+groupPts+finalPts;

  return (
    <div>
      <div className="stats-row">
        <div className="stat-card"><div className="stat-val">{total}</div><div className="stat-label">Total</div></div>
        <div className="stat-card"><div className="stat-val">{matchPts}</div><div className="stat-label">Partidos</div></div>
        <div className="stat-card"><div className="stat-val">{groupPts}</div><div className="stat-label">Grupos</div></div>
        <div className="stat-card"><div className="stat-val">{finalPts}</div><div className="stat-label">Campeón</div></div>
      </div>

      {matchRows.length>0 && (
        <div style={{marginBottom:20}}>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"#1B4F9E",letterSpacing:2,marginBottom:10}}>⚽ Puntos por Partido</div>
          {matchRows.sort((a,b)=>b.pts-a.pts).map(row=>(
            <div key={row.matchId} className="score-row">
              <div style={{flex:1}}>
                <div style={{fontWeight:700,fontSize:15}}><FlagImg team={row.match?.home||""} /> {row.match?.home||row.matchId} vs {row.match?.away||""} <FlagImg team={row.match?.away||""} /></div>
                <div style={{fontSize:14,color:"#6B7A99"}}>Tu pronóstico: {row.pred.homeGoals}-{row.pred.awayGoals} · Resultado: {row.result.homeGoals}-{row.result.awayGoals} · {row.pts >= 3 ? "3pts marcador + 1pt ganador" : row.pts === 1 ? "1pt ganador/empate" : "0pts"}</div>
              </div>
              <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:26,color:row.pts>0?"var(--green)":"var(--red)"}}>
                {row.pts>0?`+${row.pts}`:"✗"}<span style={{fontSize:14,fontFamily:"inherit"}}> pts</span>
              </div>
            </div>
          ))}
        </div>
      )}

      {groupRows.length>0 && (
        <div style={{marginBottom:20}}>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"#1B4F9E",letterSpacing:2,marginBottom:10}}>🏆 Puntos por Clasificación de Grupos</div>
          {groupRows.map(row=>(
            <div key={row.group} className="score-row">
              <div style={{flex:1}}>
                <div style={{fontWeight:700,fontSize:15}}>Grupo {row.group}</div>
                <div style={{fontSize:14,color:"#6B7A99"}}>Tu 1°: {row.pick.first} · Tu 2°: {row.pick.second} · Real 1°: {row.res.first} · Real 2°: {row.res.second}</div>
              </div>
              <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:26,color:row.pts>0?"var(--green)":"var(--red)"}}>
                {row.pts>0?`+${row.pts}`:"✗"}<span style={{fontSize:14,fontFamily:"inherit"}}> pts</span>
              </div>
            </div>
          ))}
        </div>
      )}

      {finalRows.length>0 && (
        <div style={{marginBottom:20}}>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"#1B4F9E",letterSpacing:2,marginBottom:10}}>🥇 Puntos por Pronóstico de Campeón</div>
          {finalRows.map((row,i)=>(
            <div key={i} className="score-row">
              <div style={{flex:1}}>
                <div style={{fontWeight:700,fontSize:15}}>{row.label}</div>
                <div style={{fontSize:14,color:"#6B7A99"}}>Tu elección: <FlagImg team={row.pick} /> {row.pick} · Resultado: <FlagImg team={row.result} /> {row.result}</div>
              </div>
              <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:26,color:row.pts>0?"var(--green)":"var(--red)"}}>
                {row.pts>0?`+${row.pts}`:"✗"}<span style={{fontSize:14,fontFamily:"inherit"}}> pts</span>
              </div>
            </div>
          ))}
        </div>
      )}

      {matchRows.length===0 && groupRows.length===0 && finalRows.length===0 && (
        <div style={{textAlign:"center",padding:"50px 0",color:"#6B7A99"}}>
          <div style={{fontSize:40,marginBottom:10}}>📊</div>
          <div>Aún no hay resultados publicados para calcular puntos.</div>
        </div>
      )}
    </div>
  );
}

// ============================================================
// ARMAR FASE 2 — Panel independiente para asignar equipos reales
// a todos los partidos de eliminación directa (Dieciseisavos en adelante)
// ============================================================
function ArmarFase2Tab({fase2Overrides, setFase2Overrides}) {
  const [sub, setSub] = useState("dieciseisavos");
  const [local, setLocal] = useState({});
  const [savedMsg, setSavedMsg] = useState({});

  const subPhases = [
    {key:"dieciseisavos", label:"Dieciseisavos"},
    {key:"octavos", label:"Octavos"},
    {key:"cuartos", label:"Cuartos"},
    {key:"semis", label:"Semis"},
    {key:"tercer", label:"3er Puesto"},
    {key:"final", label:"Final"},
  ];

  const matchesOfPhase = KNOCKOUT_MATCHES.filter(m => m.phase === sub);

  // Resuelve el nombre a mostrar como placeholder de ayuda: si el rival depende
  // de un partido anterior (ej "W R32_2"), muestra el cruce real si ya está armado.
  function resolvePlaceholder(code) {
    if (!code) return code;
    const m = code.match(/^W (R\d+_\d+)$/);
    if (m && fase2Overrides[m[1]]) {
      const ov = fase2Overrides[m[1]];
      return `Ganador (${ov.home} vs ${ov.away})`;
    }
    return code;
  }

  async function saveMatch(matchId, home, away) {
    const value = `${home}|${away}`;
    // Borrar override previo si existe, luego insertar (evita error de upsert sin constraint única)
    await sb.from("config").delete().eq("key", `fase2_${matchId}`);
    const {error} = await sb.from("config").insert({key:`fase2_${matchId}`, value});
    if (error) { alert("❌ Error guardando: " + error.message); return; }
    setFase2Overrides(prev => ({...prev, [matchId]: {home, away}}));
    setSavedMsg(p=>({...p,[matchId]:true}));
    setTimeout(()=>setSavedMsg(p=>({...p,[matchId]:false})),3000);
  }

  async function clearMatch(matchId) {
    if (!window.confirm("¿Borrar el cruce guardado para " + matchId + "?")) return;
    await sb.from("config").delete().eq("key", `fase2_${matchId}`);
    setFase2Overrides(prev => {
      const np = {...prev};
      delete np[matchId];
      return np;
    });
    setLocal(p => {
      const np = {...p};
      delete np[`f2_${matchId}`];
      return np;
    });
  }

  return (
    <div>
      <div style={{background:"linear-gradient(135deg,#1B4F9E,#C41E3A)",border:"none",borderRadius:14,padding:"20px 24px",marginBottom:16}}>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:32,color:"#F5C518",letterSpacing:4}}>🏗️ ARMAR FASE 2</div>
        <div style={{fontSize:15,color:"#E8EDF5",marginTop:4,lineHeight:1.7}}>
          Asigna los equipos reales a cada partido de eliminación directa conforme se vayan conociendo los resultados.
          Empieza por Dieciseisavos; cuando esos partidos tengan resultado, los de Octavos mostrarán automáticamente
          quién es el ganador para que sea más fácil armar el siguiente cruce.
        </div>
      </div>

      <div className="phase-tabs" style={{marginBottom:14}}>
        {subPhases.map(p=>(
          <button key={p.key} className={`phase-tab ${sub===p.key?"active":""}`} onClick={()=>setSub(p.key)}>{p.label}</button>
        ))}
      </div>

      <div style={{display:"flex",flexDirection:"column",gap:10}}>
        {matchesOfPhase.map(match => {
          const current = fase2Overrides[match.id] || {};
          const localKey = `f2_${match.id}`;
          const localVal = local[localKey] || {home: current.home||"", away: current.away||""};
          return (
            <div key={match.id} style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap",background:"#F8F9FC",borderRadius:10,padding:"10px 12px",border:"1px solid var(--border)"}}>
              <div style={{minWidth:110}}>
                <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:16,color:"#1B4F9E"}}>{match.id}</div>
                <div style={{fontSize:11,color:"#6B7A99"}}>{fmtDate(match.date)} · {match.time}</div>
                <div style={{fontSize:11,color:"#6B7A99",fontWeight:600}}>{resolvePlaceholder(match.home)} vs {resolvePlaceholder(match.away)}</div>
              </div>
              <select value={localVal.home} onChange={e=>setLocal(p=>({...p,[localKey]:{...localVal,home:e.target.value}}))}
                style={{padding:"6px 10px",borderRadius:8,border:"1px solid var(--border)",fontFamily:"inherit",fontSize:13,background:"#fff",color:"#1A1A2E",flex:1,minWidth:160}}>
                <option value="">-- Equipo local --</option>
                {ALL_TEAMS.map(t=><option key={t} value={t}>{t}</option>)}
              </select>
              <span style={{fontWeight:700,color:"#6B7A99"}}>vs</span>
              <select value={localVal.away} onChange={e=>setLocal(p=>({...p,[localKey]:{...localVal,away:e.target.value}}))}
                style={{padding:"6px 10px",borderRadius:8,border:"1px solid var(--border)",fontFamily:"inherit",fontSize:13,background:"#fff",color:"#1A1A2E",flex:1,minWidth:160}}>
                <option value="">-- Equipo visitante --</option>
                {ALL_TEAMS.map(t=><option key={t} value={t}>{t}</option>)}
              </select>
              <button disabled={!localVal.home || !localVal.away} onClick={()=>saveMatch(match.id, localVal.home, localVal.away)}
                style={{padding:"6px 14px",borderRadius:8,border:"1px solid #2D8A3E",
                  background:(localVal.home && localVal.away)?"rgba(45,138,62,0.1)":"#eee",
                  color:(localVal.home && localVal.away)?"#2D8A3E":"#aaa",
                  fontFamily:"inherit",fontSize:13,fontWeight:700,cursor:(localVal.home && localVal.away)?"pointer":"default"}}>
                💾 Guardar
              </button>
              {current.home && current.away && (
                <button onClick={()=>clearMatch(match.id)} style={{padding:"6px 10px",borderRadius:8,border:"1px solid #C41E3A",background:"transparent",color:"#C41E3A",fontFamily:"inherit",fontSize:13,fontWeight:700,cursor:"pointer"}}>
                  🗑️ Borrar
                </button>
              )}
              {savedMsg[match.id] && <span style={{color:"#2D8A3E",fontWeight:700,fontSize:13}}>✅ Guardado</span>}
              {current.home && current.away && <span style={{fontSize:12,color:"#2D8A3E",fontWeight:700}}>✅ {current.home} vs {current.away}</span>}
            </div>
          );
        })}
        {matchesOfPhase.length === 0 && (
          <div style={{textAlign:"center",padding:"30px",color:"#6B7A99",fontSize:15}}>
            No hay partidos definidos para esta fase.
          </div>
        )}
      </div>
    </div>
  );
}

// ============================================================
// ADMIN TAB
// ============================================================
function AdminTab({results, saveResult, groupResults, saveGroupResult, finalResults, saveFinalResult, users, addUser, getScore, predictions, groupPicks, finalPicks, setPredictions, setGroupPicks, setFinalPicks, setSurvivorPicks, setResetKey, setResults, setGroupResults, setFinalResults, setUsers, blockedDates, setBlockedDates, openedDates, setOpenedDates, clasifBlocked, setClasifBlocked, fase3Blocked, setFase3Blocked, fase2Overrides, setFase2Overrides}) {
  const [matchPhase, setMatchPhase]=useState("grupos");
  const [fechaFiltro, setFechaFiltro]=useState("");
  const fechasGrupos=[...new Set(GROUP_MATCHES.map(m=>m.date))].sort();
  const [localResults, setLocalResults]=useState({});
  const [localGroupResults, setLocalGroupResults]=useState({});
  const [localFinal, setLocalFinal]=useState(finalResults||{});
  const [deletingUser, setDeletingUser]=useState(null);
  const [deleteMsg, setDeleteMsg]=useState("");

  async function borrarPronosticos(username, tipo) {
    try {
      const esAdmin = username === "admin";
      if (tipo==="todo" || tipo==="partidos") {
        await sb.from("predictions").delete().eq("username",username);
        setPredictions(prev => { const n={...prev}; delete n[username]; return n; });
        if (esAdmin) {
          await sb.from("results").delete().neq("match_id","__never__");
          await sb.from("group_results").delete().neq("group","__never__");
          setResults({});
          setGroupResults({});
        }
      }
      if (tipo==="todo" || tipo==="grupos") {
        await sb.from("group_picks").delete().eq("username",username);
        setGroupPicks(prev => { const n={...prev}; delete n[username]; return n; });
      }
      if (tipo==="todo" || tipo==="fase3") {
        await sb.from("pronosticos_finales").delete().eq("username",username);
        setFinalPicks(prev => { const n={...prev}; delete n[username]; return n; });
        if (esAdmin) {
          await sb.from("resultados_finales").delete().eq("id",1);
          setFinalResults({});
        }
      }
      if (tipo==="todo" || tipo==="survivor") {
        await sb.from("survivor_picks").delete().eq("username",username);
        setSurvivorPicks(prev => { const n={...prev}; delete n[username]; return n; });
      }
      setDeleteMsg(`✅ Datos de ${username} eliminados`);
      setResetKey(k => k+1);
      setTimeout(()=>setDeleteMsg(""),3000);
    } catch(e) {
      setDeleteMsg("❌ Error al eliminar: "+e.message);
    }
    setDeletingUser(null);
  }

  const TARIFAS = {
    repollo_antes: 800000,
    repollo_despues: 900000,
    nuevo_antes: 900000,
    nuevo_despues: 1000000,
  };
  const [newUser, setNewUser]=useState({
    username:"", password:"Repolla2026", name:"", apodo:"",
    email:"", phone:"", city:"",
    tipo:"repollo",
    fechaEspecial: false,
    survivorEnabled:false,
    pagoSurvivor:false,
    valorPagado:800000,
  });
  const [userMsg, setUserMsg]=useState("");
  const [savedMatches, setSavedMatches]=useState({});
  const [savedGroups, setSavedGroups]=useState({});
  const [savedFinal, setSavedFinal]=useState(false);

  const subPhases=[
    {key:"grupos",label:"Grupos"},{key:"dieciseisavos",label:"Dieciseisavos"},
    {key:"octavos",label:"Octavos"},{key:"cuartos",label:"Cuartos"},{key:"semis",label:"Semis"},
    {key:"tercer",label:"3er Puesto"},{key:"final",label:"Final"},
  ];
  const matches = ALL_MATCHES.filter(m=>m.phase===matchPhase).map(m => applyFase2Override(m, fase2Overrides));

  function getR(matchId){return localResults[matchId]||results[matchId]||{};}
  function getGR(g){return localGroupResults[g]||groupResults[g]||{};}

  function saveR(matchId){
    const r=getR(matchId);
    if(!r.homeGoals && r.homeGoals!=="0"){alert("Por favor ingresa el marcador completo");return;}
    if(!r.awayGoals && r.awayGoals!=="0"){alert("Por favor ingresa el marcador completo");return;}
    saveResult(matchId, r.homeGoals, r.awayGoals, r.penaltyWinner||null);
    setSavedMatches(p=>({...p,[matchId]:true}));
    setTimeout(()=>setSavedMatches(p=>({...p,[matchId]:false})),3000);
  }

  function saveGR(g){
    const r=getGR(g);
    if(!r.first||!r.second){alert("Por favor selecciona 1° y 2° lugar");return;}
    saveGroupResult(g, r.first, r.second);
    setSavedGroups(p=>({...p,[g]:true}));
    setTimeout(()=>setSavedGroups(p=>({...p,[g]:false})),3000);
  }

  function doSaveFinal(){
    saveFinalResult({
      champion:localFinal.champion,
      runnerUp:localFinal.runnerUp,
      third:localFinal.third,
      fourth:localFinal.fourth
    });
    setSavedFinal(true);
    setTimeout(()=>setSavedFinal(false),3000);
  }

  function doAddUser(){
    if(!newUser.username||!newUser.password||!newUser.name){
      setUserMsg("⚠️ Nombre, usuario y contraseña son obligatorios");return;
    }
    if(users.find(u=>u.username===newUser.username)){
      setUserMsg("⚠️ Ese usuario ya existe");return;
    }
    const valorSurvivor = newUser.survivorEnabled ? (newUser.valorSurvivor||200000) : 0;
    const valorRepolla = newUser.valorPersonalizado ? Number(newUser.valorPersonalizado) : (newUser.tipo==="repollo"?800000:1000000);
    const valorTotal = valorRepolla + valorSurvivor;
    addUser({...newUser, valorPagado: valorTotal, pagoSurvivor: newUser.survivorEnabled});
    setNewUser({username:"",password:"Repolla2026",name:"",apodo:"",email:"",phone:"",city:"",tipo:"repollo",fechaEspecial:false,survivorEnabled:false,pagoSurvivor:false,valorPagado:800000,valorSurvivor:200000,valorPersonalizado:""});
    setUserMsg("✅ Participante agregado correctamente");
    setTimeout(()=>setUserMsg(""),4000);
  }

  return (
    <div>
      {/* Results */}
      <div style={{marginBottom:24}}>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:24,color:"#1B4F9E",letterSpacing:2,marginBottom:6}}>📋 Ingresar Resultados de Partidos</div>
        <div style={{fontSize:15,color:"#6B7A99",marginBottom:10}}>Ingresa el marcador y presiona 💾 Guardar. Verás ✅ cuando se haya guardado correctamente.</div>
        <div className="phase-tabs">
          {subPhases.map(p=><button key={p.key} className={`phase-tab ${matchPhase===p.key?"active":""}`} onClick={()=>{setMatchPhase(p.key);setFechaFiltro("");}}>{p.label}</button>)}
        </div>
        {matchPhase==="grupos" && (
          <div style={{display:"flex",gap:6,marginBottom:10,flexWrap:"wrap",alignItems:"center"}}>
            <span style={{fontSize:13,color:"var(--muted)",fontWeight:700}}>📅 Fecha:</span>
            <button onClick={()=>setFechaFiltro("")}
              style={{padding:"4px 10px",borderRadius:6,border:"1px solid",fontSize:13,cursor:"pointer",fontFamily:"inherit",
                background:fechaFiltro===""?"#1B4F9E":"transparent",borderColor:fechaFiltro===""?"#1B4F9E":"var(--border)",
                color:fechaFiltro===""?"#fff":"var(--text)"}}>Todas</button>
            {fechasGrupos.map(f=>(
              <button key={f} onClick={()=>setFechaFiltro(f)}
                style={{padding:"4px 10px",borderRadius:6,border:"1px solid",fontSize:13,cursor:"pointer",fontFamily:"inherit",
                  background:fechaFiltro===f?"#1B4F9E":"transparent",borderColor:fechaFiltro===f?"#1B4F9E":"var(--border)",
                  color:fechaFiltro===f?"#fff":"var(--text)"}}>
                {f.slice(5).replace("-","/")}
              </button>
            ))}
          </div>
        )}
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          {matches.filter(m=>matchPhase!=="grupos"||!fechaFiltro||m.date===fechaFiltro).map(match=>{
            const r=getR(match.id);
            const saved=savedMatches[match.id];
            const hasResult=results[match.id];
            const isDraw=r.homeGoals!==""&&r.awayGoals!==""&&String(r.homeGoals)===String(r.awayGoals);
            const isKO=match.fase===2;
            return (
              <div key={match.id} style={{
                display:"flex",alignItems:"center",gap:10,padding:"12px 14px",
                background: saved?"rgba(0,168,107,0.15)":hasResult?"rgba(0,168,107,0.05)":"var(--dark)",
                border:`1px solid ${saved?"var(--green)":hasResult?"rgba(0,168,107,0.4)":"var(--border)"}`,
                borderRadius:10,flexWrap:"wrap",transition:"all 0.3s"
              }}>
                <div style={{flex:1,minWidth:160}}>
                  <div style={{fontWeight:700,fontSize:14}}><FlagImg team={match.home}/> {match.home} vs {match.away} <FlagImg team={match.away}/></div>
                  <div style={{fontSize:14,color:"#6B7A99"}}>{match.id} · {fmtDate(match.date)} · {match.time}</div>
                  {hasResult && !saved && <div style={{fontSize:14,color:"#2D8A3E",fontWeight:700}}>✅ Guardado: {hasResult.homeGoals}-{hasResult.awayGoals}</div>}
                </div>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <input className="score-box" type="number" min="0" max="20"
                    value={r.homeGoals??""}
                    onChange={e=>setLocalResults(p=>({...p,[match.id]:{...getR(match.id),homeGoals:e.target.value}}))}
                    style={{borderColor: r.homeGoals!==""&&r.homeGoals!=null?"var(--gold)":"var(--border)"}}
                  />
                  <span className="score-sep">-</span>
                  <input className="score-box" type="number" min="0" max="20"
                    value={r.awayGoals??""}
                    onChange={e=>setLocalResults(p=>({...p,[match.id]:{...getR(match.id),awayGoals:e.target.value}}))}
                    style={{borderColor: r.awayGoals!==""&&r.awayGoals!=null?"var(--gold)":"var(--border)"}}
                  />
                </div>
                {isKO && isDraw && (
                  <select value={r.penaltyWinner||""} onChange={e=>setLocalResults(p=>({...p,[match.id]:{...getR(match.id),penaltyWinner:e.target.value}}))}
                    style={{padding:"5px 8px",background:"#FFFFFF",border:"1px solid var(--border)",borderRadius:8,color:"#1A1A2E",fontFamily:"inherit",fontSize:14,outline:"none"}}>
                    <option value="">-- Ganador penales --</option>
                    <option value={match.home}>{match.home}</option>
                    <option value={match.away}>{match.away}</option>
                  </select>
                )}
                <button className="btn-sm" onClick={()=>saveR(match.id)}
                  style={{background:saved?"var(--green)":"var(--accent)",minWidth:90}}>
                  {saved?"✅ Guardado":"💾 Guardar"}
                </button>
              </div>
            );
          })}
        </div>
      </div>

      {/* Group results */}
      <div style={{marginBottom:24}}>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:24,color:"#1B4F9E",letterSpacing:2,marginBottom:6}}>🏆 Clasificación de Grupos (1° y 2°)</div>
        <div style={{fontSize:15,color:"#6B7A99",marginBottom:10}}>Selecciona el 1° y 2° lugar de cada grupo al terminar la fase de grupos.</div>
        <div className="groups-grid">
          {Object.entries(GROUPS).map(([g,teams])=>{
            const gr=getGR(g);
            const saved=savedGroups[g];
            const hasResult=groupResults[g];
            return (
              <div key={g} className="group-card" style={{border:`1px solid ${saved?"var(--green)":hasResult?"rgba(0,168,107,0.4)":"var(--border)"}`,background:saved?"rgba(0,168,107,0.1)":"var(--dark)"}}>
                <div className="group-label">Grupo {g}</div>
                <div style={{fontSize:14,color:"#6B7A99",marginBottom:8}}>{teams.join(" · ")}</div>
                {hasResult && !saved && <div style={{fontSize:14,color:"#2D8A3E",fontWeight:700,marginBottom:6}}>✅ {hasResult.first} · {hasResult.second}</div>}
                <div className="field" style={{marginBottom:8}}><label>1° Lugar</label>
                  <select value={gr.first||""} onChange={e=>setLocalGroupResults(p=>({...p,[g]:{...getGR(g),first:e.target.value}}))}>
                    <option value="">-- elige --</option>{teams.map(t=><option key={t} value={t}>{t}</option>)}
                  </select></div>
                <div className="field" style={{marginBottom:10}}><label>2° Lugar</label>
                  <select value={gr.second||""} onChange={e=>setLocalGroupResults(p=>({...p,[g]:{...getGR(g),second:e.target.value}}))}>
                    <option value="">-- elige --</option>{teams.map(t=><option key={t} value={t}>{t}</option>)}
                  </select></div>
                <button className="btn-sm" style={{width:"100%",background:saved?"var(--green)":"var(--accent)"}} onClick={()=>saveGR(g)}>
                  {saved?"✅ Guardado":"💾 Guardar"}
                </button>
              </div>
            );
          })}
        </div>
      </div>

      {/* Final results */}
      <div style={{marginBottom:24}}>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:24,color:"#1B4F9E",letterSpacing:2,marginBottom:6}}>🥇 Resultados Finales del Torneo</div>
        <div style={{fontSize:15,color:"#6B7A99",marginBottom:10}}>Solo al terminar el torneo. Campeón vale 12pts, Subcampeón 9pts, 3° 7pts, 4° 5pts.</div>
        <div className="final-grid">
          {[{k:"champion",l:"🥇 Campeón",pts:12},{k:"runnerUp",l:"🥈 Subcampeón",pts:9},{k:"third",l:"🥉 3er Puesto",pts:7},{k:"fourth",l:"4️⃣ 4to Puesto",pts:5}].map(f=>(
            <div key={f.k} className="final-pick">
              <div className="final-pick-label">{f.l} <span className="pts-badge">{f.pts}pts</span></div>
              {finalResults?.[f.k] && <div style={{fontSize:14,color:"#2D8A3E",marginBottom:4}}>✅ Actual: {finalResults[f.k]}</div>}
              <select value={localFinal?.[f.k]||""} onChange={e=>setLocalFinal(p=>({...p,[f.k]:e.target.value}))}
                style={{width:"100%",padding:9,background:"#F8F9FC",border:"1px solid var(--border)",borderRadius:8,color:"#1A1A2E",fontFamily:"inherit",fontSize:15,outline:"none"}}>
                <option value="">-- elige equipo --</option>
                {TEAMS_LIST.map(t=><option key={t} value={t}>{t}</option>)}
              </select>
            </div>
          ))}
        </div>
        <div style={{display:"flex",alignItems:"center",gap:12,marginTop:12}}>
          <button className="btn-save" onClick={doSaveFinal} style={{background:savedFinal?"var(--green)":"var(--green)"}}>
            {savedFinal?"✅ ¡Guardado!":"💾 Guardar Resultados Finales"}
          </button>
          {savedFinal && <span style={{color:"#2D8A3E",fontSize:15,fontWeight:700}}>✅ Los puntos se actualizaron para todos los participantes</span>}
        </div>
      </div>

      {/* Add user */}
      <div style={{marginBottom:24}}>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:24,color:"#1B4F9E",letterSpacing:2,marginBottom:6}}>👤 Agregar Participante</div>
        <div style={{fontSize:15,color:"#6B7A99",marginBottom:10}}>Completa los datos del formulario de inscripción. Solo Nombre, Usuario y Contraseña son obligatorios.</div>
        <div style={{background:"#F8F9FC",border:"1px solid var(--border)",borderRadius:14,padding:"20px"}}>

          {/* Fila 1: Datos personales */}
          <div style={{fontSize:14,fontWeight:700,color:"#1B4F9E",letterSpacing:2,textTransform:"uppercase",marginBottom:10}}>📋 Datos Personales</div>
          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:12}}>
            <div className="field" style={{flex:2,minWidth:160,marginBottom:0}}>
              <label>Nombre completo *</label>
              <input value={newUser.name} onChange={e=>setNewUser(p=>({...p,name:e.target.value}))} placeholder="Ej: María López" />
            </div>
            <div className="field" style={{flex:1,minWidth:120,marginBottom:0}}>
              <label>Apodo</label>
              <input value={newUser.apodo} onChange={e=>setNewUser(p=>({...p,apodo:e.target.value}))} placeholder="Ej: La Reina" />
            </div>
            <div className="field" style={{flex:1,minWidth:120,marginBottom:0}}>
              <label>Ciudad</label>
              <input value={newUser.city} onChange={e=>setNewUser(p=>({...p,city:e.target.value}))} placeholder="Ej: Bogotá" />
            </div>
          </div>
          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:16}}>
            <div className="field" style={{flex:1,minWidth:160,marginBottom:0}}>
              <label>📧 Correo</label>
              <input value={newUser.email} onChange={e=>setNewUser(p=>({...p,email:e.target.value}))} placeholder="correo@ejemplo.com" />
            </div>
            <div className="field" style={{flex:1,minWidth:130,marginBottom:0}}>
              <label>📱 Celular</label>
              <input value={newUser.phone} onChange={e=>setNewUser(p=>({...p,phone:e.target.value}))} placeholder="3001234567" />
            </div>
          </div>

          {/* Fila 2: Tipo y pago */}
          <div style={{fontSize:14,fontWeight:700,color:"#1B4F9E",letterSpacing:2,textTransform:"uppercase",marginBottom:10}}>💰 Tipo y Pago</div>
          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:16,alignItems:"flex-end"}}>
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              <label style={{fontSize:14,fontWeight:700,color:"#6B7A99",letterSpacing:1,textTransform:"uppercase"}}>¿RePoLLo o NueVón?</label>
              <div style={{display:"flex",gap:6}}>
                {["repollo","nuevo"].map(t=>(
                  <button key={t} onClick={()=>setNewUser(p=>({...p,tipo:t}))}
                    style={{padding:"8px 14px",borderRadius:8,border:"1px solid",fontFamily:"inherit",fontSize:15,fontWeight:700,cursor:"pointer",
                      background:newUser.tipo===t?"rgba(0,168,107,0.2)":"transparent",
                      borderColor:newUser.tipo===t?"var(--green)":"var(--border)",
                      color:newUser.tipo===t?"var(--green)":"var(--muted)"}}>
                    {t==="repollo"?"🥬 RePoLLo":"🆕 NueVón"}
                  </button>
                ))}
              </div>
              <div style={{fontSize:14,color:"#6B7A99"}}>
                {newUser.tipo==="repollo"?"RePoLLo antiguo · tarifa normal":"NueVón · primera vez"}
              </div>
            </div>
            <div className="field" style={{flex:1,minWidth:140,marginBottom:0}}>
              <label>💵 Valor a pagar (manual)</label>
              <input value={newUser.valorPersonalizado} onChange={e=>setNewUser(p=>({...p,valorPersonalizado:e.target.value}))}
                placeholder="Dejar vacío para valor estándar" type="number"/>
            </div>
          </div>

          {/* Fila 3: Login y Survivor */}
          <div style={{fontSize:14,fontWeight:700,color:"#1B4F9E",letterSpacing:2,textTransform:"uppercase",marginBottom:10}}>🔐 Acceso y Survivor</div>
          <div style={{display:"flex",gap:10,flexWrap:"wrap",alignItems:"flex-end"}}>
            <div className="field" style={{flex:1,minWidth:120,marginBottom:0}}>
              <label>Usuario (para login) *</label>
              <input value={newUser.username} onChange={e=>setNewUser(p=>({...p,username:e.target.value.toLowerCase().trim()}))} placeholder="Ej: maria" />
            </div>
            <div className="field" style={{flex:1,minWidth:120,marginBottom:0}}>
              <label>Contraseña *</label>
              <input value={newUser.password} onChange={e=>setNewUser(p=>({...p,password:e.target.value}))} placeholder="Ej: repolla123" />
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:4}}>
              <label style={{fontSize:14,fontWeight:700,color:"#6B7A99",letterSpacing:1,textTransform:"uppercase"}}>🔥 Survivor</label>
              <button onClick={()=>setNewUser(p=>({...p,survivorEnabled:!p.survivorEnabled,pagoSurvivor:!p.survivorEnabled}))}
                style={{padding:"10px 20px",borderRadius:8,border:"1px solid",fontFamily:"inherit",fontSize:15,fontWeight:700,cursor:"pointer",
                  background:newUser.survivorEnabled?"rgba(196,30,58,0.1)":"transparent",
                  borderColor:newUser.survivorEnabled?"#C41E3A":"#E0E6F0",
                  color:newUser.survivorEnabled?"#C41E3A":"#6B7A99"}}>
                {newUser.survivorEnabled?"🔥 SÍ juega":"❌ NO juega"}
              </button>
            </div>
            {newUser.survivorEnabled && (
              <div className="field" style={{flex:1,minWidth:140,marginBottom:0}}>
                <label>💵 Valor Survivor</label>
                <input value={newUser.valorSurvivor||200000} onChange={e=>setNewUser(p=>({...p,valorSurvivor:Number(e.target.value)}))}
                  type="number" placeholder="200000"/>
              </div>
            )}
            <button className="btn-save" onClick={doAddUser} style={{padding:"11px 24px",fontSize:16}}>
              ➕ Agregar RePoLLo
            </button>
          </div>

          {/* Pago */}
          <div style={{marginTop:14,padding:"14px 16px",background:"#F8F9FC",borderRadius:12,border:"1px solid #E0E6F0"}}>
            <div style={{fontSize:14,fontWeight:700,color:"#1B4F9E",letterSpacing:2,textTransform:"uppercase",marginBottom:10}}>💰 Pago</div>
            <div style={{display:"flex",gap:10,flexWrap:"wrap",alignItems:"center"}}>
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                <label style={{fontSize:14,fontWeight:700,color:"#6B7A99",letterSpacing:1,textTransform:"uppercase"}}>Fecha de inscripción</label>
                <div style={{display:"flex",gap:6}}>
                  {[{k:false,l:"Antes 15 mayo"},{k:true,l:"Después 15 mayo"}].map(f=>(
                    <button key={String(f.k)} onClick={()=>{
                      const val = f.k
                        ? (newUser.tipo==="repollo" ? 900000 : 1000000)
                        : (newUser.tipo==="repollo" ? 800000 : 900000);
                      setNewUser(p=>({...p,fechaEspecial:f.k,valorPagado:val}));
                    }} style={{padding:"7px 12px",borderRadius:8,border:"1px solid",fontFamily:"inherit",fontSize:14,fontWeight:700,cursor:"pointer",
                      background:newUser.fechaEspecial===f.k?"rgba(27,79,158,0.15)":"#fff",
                      borderColor:newUser.fechaEspecial===f.k?"#1B4F9E":"#E0E6F0",
                      color:newUser.fechaEspecial===f.k?"#1B4F9E":"#6B7A99"}}>
                      {f.l}
                    </button>
                  ))}
                </div>
              </div>
              <div style={{background:"#E3EFFF",borderRadius:10,padding:"8px 16px",textAlign:"center"}}>
                <div style={{fontSize:12,color:"#6B7A99",marginBottom:2}}>RePoLLa</div>
                <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:24,color:"#1B4F9E"}}>
                  ${(newUser.valorPagado||0).toLocaleString("es-CO")}
                </div>
              </div>
              {newUser.survivorEnabled && (
                <div style={{background:"#FFEBEE",borderRadius:10,padding:"8px 16px",textAlign:"center"}}>
                  <div style={{fontSize:12,color:"#6B7A99",marginBottom:2}}>Survivor</div>
                  <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:24,color:"#C41E3A"}}>+$200.000</div>
                </div>
              )}
              <div style={{background:"#E8F5E9",borderRadius:10,padding:"8px 16px",textAlign:"center"}}>
                <div style={{fontSize:12,color:"#6B7A99",marginBottom:2}}>Total</div>
                <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:24,color:"#2D8A3E"}}>
                  ${((newUser.valorPagado||0)+(newUser.survivorEnabled?200000:0)).toLocaleString("es-CO")}
                </div>
              </div>
            </div>
          </div>

          {userMsg && (
            <div style={{marginTop:12,fontSize:15,fontWeight:700,
              color:userMsg.startsWith("✅")?"var(--green)":"var(--red)",
              padding:"10px 14px",
              background:userMsg.startsWith("✅")?"rgba(0,168,107,0.1)":"rgba(232,64,64,0.1)",
              borderRadius:8,border:`1px solid ${userMsg.startsWith("✅")?"var(--green)":"var(--red)"}`}}>
              {userMsg}
            </div>
          )}
        </div>
      </div>

      {/* Participants list */}
      <div>
        <div style={{display:"flex",alignItems:"center",gap:12,flexWrap:"wrap",marginBottom:10}}>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:24,color:"#1B4F9E",letterSpacing:2}}>
            📊 Participantes ({users.filter(u=>!u.isAdmin&&!u.isDemo).length} / 100)
          </div>
          {/* ── Controles de bloqueo ── */}
          <div style={{background:"rgba(196,30,58,0.06)",border:"1px solid rgba(196,30,58,0.3)",borderRadius:12,padding:"14px 16px",marginBottom:12}}>
            <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:18,color:"#C41E3A",letterSpacing:1,marginBottom:10}}>🔒 Control de bloqueo de envíos</div>

            {/* Fase 1 por fecha — 3 estados: Auto / Forzar Abierto / Forzar Cerrado */}
            <div style={{marginBottom:10}}>
              <div style={{fontSize:13,fontWeight:700,color:"#1A1A2E",marginBottom:6}}>⚽ Fase 1 — Estado de envío por fecha (clic para cambiar: Auto → Abierto → Cerrado → Auto):</div>
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                {[...new Set(GROUP_MATCHES.map(m=>m.date))].sort().map(d=>{
                  const isBlocked = blockedDates.includes(d);
                  const isOpened = openedDates.includes(d);
                  const state = isBlocked ? "closed" : isOpened ? "open" : "auto";
                  const styles = {
                    auto:   {bg:"transparent", border:"var(--border)", color:"var(--text)", icon:"⚙️", label:"Auto"},
                    open:   {bg:"#2D8A3E", border:"#2D8A3E", color:"#fff", icon:"🔓", label:"Abierto"},
                    closed: {bg:"#C41E3A", border:"#C41E3A", color:"#fff", icon:"🔒", label:"Cerrado"},
                  };
                  const s = styles[state];
                  return (
                    <button key={d} onClick={async()=>{
                      let newBlocked = blockedDates.filter(x=>x!==d);
                      let newOpened = openedDates.filter(x=>x!==d);
                      if (state === "auto") {
                        newOpened = [...newOpened, d]; // auto -> abierto
                      } else if (state === "open") {
                        newBlocked = [...newBlocked, d]; // abierto -> cerrado
                      } // cerrado -> auto (ambos arrays ya quedan sin la fecha)
                      setBlockedDates(newBlocked);
                      setOpenedDates(newOpened);
                      await saveConfig("blockedDates", newBlocked.join(","));
                      await saveConfig("openedDates", newOpened.join(","));
                    }} style={{padding:"5px 10px",borderRadius:8,border:`1px solid ${s.border}`,fontSize:12,fontWeight:700,cursor:"pointer",
                      background:s.bg, color:s.color}}>
                      {s.icon} {d.slice(5)} · {s.label}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Clasificación */}
            <div style={{display:"flex",gap:10,alignItems:"center",marginBottom:8}}>
              <span style={{fontSize:13,fontWeight:700}}>📊 Clasificación grupos:</span>
              <button onClick={async()=>{
                const newVal = !clasifBlocked;
                setClasifBlocked(newVal);
                await saveConfig("clasifBlocked", newVal?"true":"false");
              }} style={{padding:"6px 14px",borderRadius:8,border:"1px solid",fontSize:13,fontWeight:700,cursor:"pointer",
                background:clasifBlocked?"#C41E3A":"rgba(45,138,62,0.1)",
                borderColor:clasifBlocked?"#C41E3A":"#2D8A3E",
                color:clasifBlocked?"#fff":"#2D8A3E"}}>
                {clasifBlocked?"🔒 Bloqueado — clic para abrir":"🔓 Abierto — clic para bloquear"}
              </button>
            </div>

            {/* Fase 3 */}
            <div style={{display:"flex",gap:10,alignItems:"center"}}>
              <span style={{fontSize:13,fontWeight:700}}>🏆 Fase 3 (podio):</span>
              <button onClick={async()=>{
                const newVal = !fase3Blocked;
                setFase3Blocked(newVal);
                await saveConfig("fase3Blocked", newVal?"true":"false");
              }} style={{padding:"6px 14px",borderRadius:8,border:"1px solid",fontSize:13,fontWeight:700,cursor:"pointer",
                background:fase3Blocked?"#C41E3A":"rgba(45,138,62,0.1)",
                borderColor:fase3Blocked?"#C41E3A":"#2D8A3E",
                color:fase3Blocked?"#fff":"#2D8A3E"}}>
                {fase3Blocked?"🔒 Bloqueado — clic para abrir":"🔓 Abierto — clic para bloquear"}
              </button>
            </div>
          </div>

          {/* Selector fecha + pendientes por fecha */}
          <div style={{display:"flex",gap:6,alignItems:"center",flexWrap:"wrap"}}>
            <select value={fechaFiltro} onChange={e=>setFechaFiltro(e.target.value)}
              style={{padding:"6px 10px",borderRadius:8,border:"1px solid var(--border)",fontFamily:"inherit",fontSize:13,background:"#F8F9FC",color:"#1A1A2E"}}>
              <option value="">-- Elegir fecha --</option>
              {[...new Set(GROUP_MATCHES.map(m=>m.date))].sort().map(d=><option key={d} value={d}>{d}</option>)}
            </select>
            <button disabled={!fechaFiltro} onClick={async () => {
              // Consultar Supabase filtrando solo los partidos de la fecha seleccionada
              const matchIds = GROUP_MATCHES.filter(m=>m.date===fechaFiltro).map(m=>m.id);
              const { data: freshPreds, error: fpErr } = await sb.from("predictions")
                .select("username,match_id,home_goals,away_goals")
                .in("match_id", matchIds);
              if (fpErr) { alert("❌ Error consultando Supabase: " + fpErr.message); return; }
              const predMap = {};
              if (freshPreds) {
                freshPreds.forEach(p => {
                  if (!predMap[p.username]) predMap[p.username] = {};
                  predMap[p.username][p.match_id] = {homeGoals: p.home_goals, awayGoals: p.away_goals};
                });
              }
              const partidos = GROUP_MATCHES.filter(m=>m.date===fechaFiltro);
              const jugadores = users.filter(u=>!u.isAdmin&&!u.isDemo);
              const rows = [["Jugador","Apodo","Usuario","Partido","¿Envió pronóstico?"]];
              jugadores.forEach(u => {
                const preds = predMap[u.username]||{};
                partidos.forEach(m => {
                  const p = preds[m.id];
                  const envio = p && p.homeGoals!==null && p.homeGoals!=="" && p.awayGoals!==null && p.awayGoals!=="" ? "✅ Enviado" : "❌ Pendiente";
                  rows.push([u.name, u.apodo||u.name, u.username, `${m.home} vs ${m.away}`, envio]);
                });
              });
              const csv = rows.map(r=>r.map(c=>`"${String(c).replace(/"/g,'""')}"`).join(",")).join("\n");
              const blob = new Blob(["\uFEFF"+csv],{type:"text/csv;charset=utf-8;"});
              const a = document.createElement("a");
              a.href = URL.createObjectURL(blob);
              a.download = `Pendientes_${fechaFiltro}.csv`;
              a.click();
              URL.revokeObjectURL(a.href);
            }} style={{padding:"6px 12px",borderRadius:8,border:"1px solid #1B4F9E",background:fechaFiltro?"rgba(27,79,158,0.08)":"#eee",color:fechaFiltro?"#1B4F9E":"#aaa",fontFamily:"inherit",fontSize:13,fontWeight:700,cursor:fechaFiltro?"pointer":"default"}}>
              📅 Pendientes por fecha
            </button>
          </div>
          <button onClick={() => {
            const jugadores = users.filter(u => !u.isAdmin && !u.isDemo);
            const rows = [];
            rows.push(["Jugador","Apodo","Usuario","Tipo","Fase 1 (partidos)","Clasificación grupos","Fase 3 (podio)","Clave cambiada"]);
            jugadores.forEach(u => {
              const predsU = predictions[u.username] || {};
              const totalF1 = GROUP_MATCHES.length;
              const enviados = GROUP_MATCHES.filter(m => {
                const p = predsU[m.id];
                return p && p.homeGoals !== "" && p.homeGoals != null && p.awayGoals !== "" && p.awayGoals != null;
              }).length;
              const pendientesF1 = totalF1 - enviados;
              const gPicks = groupPicks[u.username] || {};
              const gruposTotales = 12;
              const gruposEnviados = Object.keys(gPicks).length;
              const pendientesGrupos = gruposTotales - gruposEnviados;
              const fp = finalPicks[u.username];
              const fase3Ok = fp && fp.champion ? "✅ Enviado" : "❌ Pendiente";
              const claveOk = u.password !== "Repolla2026" ? "✅ Cambiada" : "❌ Sin cambiar";
              rows.push([
                u.name, u.apodo||u.name, u.username, u.tipo==="repollo"?"RePoLLo":"NueVón",
                pendientesF1===0 ? "✅ Completo" : `❌ Faltan ${pendientesF1}/${totalF1}`,
                pendientesGrupos===0 ? "✅ Completo" : `❌ Faltan ${pendientesGrupos}/${gruposTotales} grupos`,
                fase3Ok, claveOk
              ]);
            });
            const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g,'""')}"`).join(",")).join("\n");
            const blob = new Blob(["﻿"+csv], {type:"text/csv;charset=utf-8;"});
            const a = document.createElement("a");
            a.href = URL.createObjectURL(blob);
            a.download = `RePoLLa_Pendientes_${new Date().toISOString().slice(0,10)}.csv`;
            a.click();
            URL.revokeObjectURL(a.href);
          }} style={{padding:"7px 14px",borderRadius:8,border:"1px solid #1B4F9E",background:"rgba(27,79,158,0.08)",color:"#1B4F9E",fontFamily:"inherit",fontSize:13,fontWeight:700,cursor:"pointer"}}>
            📥 Exportar pendientes
          </button>
          <button onClick={async () => {
            const sinCambio = users.filter(u => !u.isAdmin && !u.isDemo && u.password === "Repolla2026");
            if (sinCambio.length === 0) { alert("✅ Todos los jugadores ya cambiaron su clave."); return; }
            if (!window.confirm(`¿Forzar cambio de clave a ${sinCambio.length} jugadores que aún tienen la clave por defecto?`)) return;
            for (const u of sinCambio) {
              await sb.from("users").update({must_change_password: true}).eq("username", u.username);
            }
            setUsers(prev => prev.map(u => (!u.isAdmin && u.password === "Repolla2026") ? {...u, mustChangePassword: true} : u));
            alert(`✅ Se forzó cambio de clave a ${sinCambio.length} jugadores. Al próximo ingreso deberán crear una nueva contraseña.`);
          }} style={{padding:"7px 14px",borderRadius:8,border:"1px solid #C41E3A",background:"rgba(196,30,58,0.08)",color:"#C41E3A",fontFamily:"inherit",fontSize:13,fontWeight:700,cursor:"pointer"}}>
            🔑 Forzar cambio de clave ({users.filter(u=>!u.isAdmin&&!u.isDemo&&u.password==="Repolla2026").length} pendientes)
          </button>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {users.filter(u=>!u.isAdmin&&!u.isDemo).map((u,i)=>(
            <div key={u.username} className="lb-row">
              <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"#6B7A99",minWidth:28}}>{i+1}</div>
              <div className="avatar" style={{background:avatarColor(u.apodo||u.name),width:34,height:34,fontSize:14}}>{initials(u.apodo||u.name)}</div>
              <div style={{flex:1}}>
                <div style={{fontSize:15,fontWeight:600}}>
                  {u.name} {u.apodo && <span style={{fontSize:14,color:"#6B7A99"}}>"{u.apodo}"</span>}
                </div>
                <div style={{fontSize:14,color:"#6B7A99",marginTop:2}}>
                  @{u.username}
                  {u.city && <span> · 📍{u.city}</span>}
                  {u.tipo==="repollo" ? <span style={{color:"#2d8a3e"}}> · 🥬 RePoLLo</span> : <span style={{color:"#1B4F9E"}}> · 🆕 NueVón</span>}
                  {u.survivorEnabled && <span style={{color:"#1B4F9E"}}> · 🔥 Survivor</span>}
                </div>
                <div style={{fontSize:12,color:"#6B7A99",marginTop:1}}>
                  {u.email && <span>📧 {u.email} </span>}
                  {u.phone && <span>📱 {u.phone}</span>}
                  {u.password === "Repolla2026"
                    ? <span style={{marginLeft:4,color:"#C41E3A",fontWeight:700}}>🔑 Clave sin cambiar</span>
                    : <span style={{marginLeft:4,color:"#2D8A3E",fontWeight:600}}>✅ Clave personalizada</span>}
                </div>
              </div>
              <div style={{textAlign:"right"}}>
                <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:26,color:"#1B4F9E"}}>
                  {getScore(u.username)}<span style={{fontSize:14,fontFamily:"inherit",color:"#6B7A99",marginLeft:2}}>pts</span>
                </div>
                {u.valorPersonalizado && <div style={{fontSize:12,color:"#2D8A3E"}}>${parseInt(u.valorPersonalizado).toLocaleString("es-CO")}</div>}
              </div>
            </div>
          ))}
          {users.filter(u=>!u.isAdmin&&!u.isDemo).length===0 && (
            <div style={{textAlign:"center",padding:"30px",color:"#6B7A99",fontSize:15}}>
              Aún no hay participantes. ¡Agrega el primero arriba!
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ============================================================
// MAÑANA TAB
// ============================================================
function MananaTab({currentUser, predictions, results, savePrediction, blockedDates=[], openedDates=[]}) {
  const realToday = new Date(new Date().toLocaleString("en-US",{timeZone:"America/Bogota"})).toISOString().slice(0,10);
  const MUNDIAL_START = "2026-06-11";
  // Antes del inicio: mostrar el 12 jun (jornada 1 segundo día)
  const tomorrow = realToday < MUNDIAL_START ? "2026-06-12" : tomorrowStr();
  const isAnchored = realToday < MUNDIAL_START;
  const matches = ALL_MATCHES.filter(m => m.date === tomorrow && m.fase <= 2);
  return (
    <div>
      <div className="phase-banner f1">
        🌅 Partidos de mañana · <strong>{fmtDate(tomorrow)}</strong>
        {isAnchored && <span style={{marginLeft:8,fontSize:13,color:"#F0B429",fontWeight:600}}>· Previa — envía tu pronóstico</span>}
      </div>
      {matches.length === 0 ? (
        <div style={{textAlign:"center",padding:"60px 0",color:"#6B7A99"}}>
          <div style={{fontSize:48,marginBottom:12}}>🌅</div>
          <div style={{fontSize:18,fontWeight:600}}>No hay partidos mañana</div>
          <div style={{fontSize:15,marginTop:6,color:"#6B7A99"}}>Disfruta el descanso 😊</div>
        </div>
      ) : (
        <MatchList matches={matches} predictions={predictions} results={results}
          savePrediction={savePrediction} allPredictions={null} showScores={false} blockedDates={blockedDates} openedDates={openedDates} />
      )}
    </div>
  );
}

// ============================================================
// SURVIVOR TAB
// ============================================================
function SurvivorTab({currentUser, users, survivorPicks, setSurvivorPicks, survivorTestDate, setSurvivorTestDate, survivorBlockedDates, setSurvivorBlockedDates, survivorActiveJornadas, setSurvivorActiveJornadas}) {
  const isAdmin = currentUser.isAdmin;
  const survivorUsers = users.filter(u => !u.isAdmin && !u.isDemo && u.survivorEnabled === true);
  const groupDates = [...new Set(GROUP_MATCHES.map(m => m.date))].sort();
  // Jornada seleccionada en "Ver Survivor de..." (admin)
  const [viewJornada, setViewJornada] = useState("");
  // Panel ingreso manual de pick
  const [manualUser, setManualUser] = useState("");
  const [manualTeam, setManualTeam] = useState("");
  const [manualPickDate, setManualPickDate] = useState("");
  const [manualMsg, setManualMsg] = useState("");
  const realToday = new Date(new Date().toLocaleString("en-US",{timeZone:"America/Bogota"})).toISOString().slice(0,10);
  const MUNDIAL_START = "2026-06-11";
  // survivorMaxDate = fecha hasta la que el admin habilitó envío (ej: "2026-06-12")
  const survivorMaxDate = (survivorTestDate && survivorTestDate !== "off") ? survivorTestDate : null;

  // UNIFIED_DAYS se define más abajo, pero necesitamos getJornadaKey aquí
  // Mapeo inline para calcular jornadaKey de realToday
  const JORNADA_MAP = {
    '2026-06-11': '2026-06-11', '2026-06-12': '2026-06-11',
    '2026-06-28': '2026-06-28', '2026-06-29': '2026-06-28',
    '2026-07-09': '2026-07-09', '2026-07-10': '2026-07-09',
  };
  const getJornadaKeyEarly = (d) => JORNADA_MAP[d] || d;

  // today = jornada que el admin habilitó (survivorMaxDate), SIEMPRE.
  // El Survivor funciona "un día antes": el admin habilita la fecha del partido
  // siguiente y los jugadores ven y eligen los equipos de esa jornada.
  // today = última jornada habilitada (para compatibilidad con historial y admin)
  const today = survivorMaxDate ? getJornadaKeyEarly(survivorMaxDate) : MUNDIAL_START;

  const survivorClose = survivorMaxDate ? new Date(survivorMaxDate + "T23:00:00-05:00") : null;
  const survivorClosed = survivorClose ? new Date() >= survivorClose : true;

  // Todas las jornadas habilitadas por el admin (activas + survivorMaxDate)
  const allActiveJornadas = [...new Set([
    ...survivorActiveJornadas,
    ...(survivorMaxDate && !survivorClosed ? [getJornadaKeyEarly(survivorMaxDate)] : [])
  ])].filter(j => !survivorBlockedDates.includes(j)).sort();

  // canPickToday: hay al menos una jornada activa no bloqueada
  const canPickToday = allActiveJornadas.length > 0;

  // Polling cada 30s para que jugadores vean cambios del admin en tiempo real
  useEffect(() => {
    if (isAdmin) return; // admin no necesita polling, él mismo cambia el valor
    const interval = setInterval(async () => {
      try {
        const { data: cfg } = await sb.from("config").select("*").eq("key","survivorTestDate").single();
        if (cfg && cfg.value !== survivorTestDate) {
          setSurvivorTestDate(cfg.value);
        }
      } catch(e) {}
    }, 30000);
    return () => clearInterval(interval);
  }, [survivorTestDate, isAdmin]);

  async function setSurvivorMaxDate(date) {
    setSurvivorTestDate(date);
    await saveConfig("survivorTestDate", date);
  }

  // Verifica picks faltantes para UNA jornada específica elegida por el admin
  async function checkMissingPicks(jornadaKey) {
    if (!jornadaKey) { alert("⚠️ Elige una jornada primero."); return; }
    let sinPick = 0;
    // Solo procesar jugadores que siguen VIVOS (menos de 2 vidas perdidas)
    const jugadoresVivos = survivorUsers.filter(u => getLivesLost(u.username) < 2);
    for (const u of jugadoresVivos) {
      const userPicks = survivorPicks[u.username] || {};
      const hasPick = Object.keys(userPicks).some(d => getJornadaKey(d) === jornadaKey);
      if (!hasPick) {
        const {error} = await sb.from("survivor_picks").insert({
          username: u.username, date: jornadaKey, team: "Sin pick",
          failed: true, result: "nopick", match_id: jornadaKey
        });
        if (!error) {
          setSurvivorPicks(prev => ({...prev, [u.username]: {
            ...(prev[u.username]||{}), [jornadaKey]: {team:"Sin pick",failed:true,result:"nopick"}
          }}));
          sinPick++;
        }
      }
    }
    alert(sinPick > 0
      ? `✅ ${sinPick} jugadores VIVOS marcados sin pick en jornada ${jornadaKey} (eliminados ignorados)`
      : `✅ Todos los jugadores VIVOS enviaron pick en la jornada ${jornadaKey}`);
  }

  // advanceTestDate eliminado

  // Jornadas unificadas: fecha real -> fecha clave de la jornada
  const UNIFIED_DAYS = {
    '2026-06-11': '2026-06-11', // Jornada 1
    '2026-06-12': '2026-06-11', // Jornada 1 (mismo bloque)
    '2026-06-28': '2026-06-28', // Jornada 17
    '2026-06-29': '2026-06-28', // Jornada 17 (mismo bloque)
    '2026-07-09': '2026-07-09', // Jornada 24
    '2026-07-10': '2026-07-09', // Jornada 24 (mismo bloque)
  };
  // Partido 3er puesto NO cuenta para Survivor
  const EXCLUDED_SURVIVOR = ['2026-07-12'];
  // Jornada 1 = sin eliminaciones aunque pierda
  const isJornada1 = (date) => date === '2026-06-11' || date === '2026-06-12';
  // Obtener clave de jornada (para jornadas unificadas usar la primera fecha)
  const getJornadaKey = (date) => UNIFIED_DAYS[date] || date;

  // ── Helper: get lives lost for a user ──────────────────────
  function getLivesLost(username) {
    const picks = survivorPicks[username] || {};
    return Object.entries(picks).filter(([date, p]) => 
      p.failed && !EXCLUDED_SURVIVOR.includes(date)
    ).length;
  }

  function isUserAlive(username) { return getLivesLost(username) < 2; }

  // ── My data ─────────────────────────────────────────────────
  const myPicks = survivorPicks[currentUser.username] || {};
  // El equipo queda "usado" apenas se envía el pick (no se puede repetir en jornadas futuras)
  // Equipos usados = todos los picks enviados (sin importar la key de fecha)
  const myUsedTeams = Object.values(myPicks).map(p => p.team).filter(Boolean);
  // Pick de la jornada actual = cualquier pick cuya fecha mapea a todayJornadaKey
  // Esto cubre picks guardados con keys incorrectas de versiones anteriores
  const myLivesLost = getLivesLost(currentUser.username);
  const myAlive = myLivesLost < 2;

  // Para jornadas unificadas, mostrar equipos de ambos días
  const todayJornadaKey = getJornadaKey(today);
  const jornadaDates = Object.entries(UNIFIED_DAYS)
    .filter(([d, k]) => k === todayJornadaKey)
    .map(([d]) => d);
  const jornadaMatchDates = jornadaDates.length > 0 ? jornadaDates : [today];
  const todayMatches = GROUP_MATCHES.filter(m => jornadaMatchDates.includes(m.date));
  const todayTeams = [...new Set(todayMatches.flatMap(m => [m.home, m.away]))];
  // Available = playing in this jornada AND not already used
  const availableTeams = todayTeams.filter(t => !myUsedTeams.includes(t));

  const [selectedTeam, setSelectedTeam] = useState("");
  const [saved, setSaved] = useState(false);

  async function savePick() {
    if (!selectedTeam) return;
    if (EXCLUDED_SURVIVOR.includes(todayJornadaKey)) return;
    // Siempre guardar con jornadaKey (fecha canónica de la jornada)
    const pickDate = todayJornadaKey;
    setSurvivorPicks(prev => ({
      ...prev,
      [currentUser.username]: {
        ...(prev[currentUser.username] || {}),
        [pickDate]: { team: selectedTeam, failed: false, result: null }
      }
    }));
    try {
      await sb.from("survivor_picks").delete().eq("username", currentUser.username).eq("date", pickDate);
      const {error: spErr} = await sb.from("survivor_picks").insert({
        username: currentUser.username,
        date: pickDate,
        team: selectedTeam,
        failed: false,
        result: null,
        match_id: pickDate
      });
      if (spErr) alert("❌ Error guardando survivor: " + spErr.message);
    } catch(e) { alert("❌ Excepción survivor: " + e.message); }
    setSaved(true);
    setSelectedTeam("");
    setTimeout(() => setSaved(false), 2500);
  }

  // ── Admin: mark result for a pick ───────────────────────────
  async function markResult(username, date, result) {
    const pick = survivorPicks[username]?.[date];
    if (!pick) return;
    // Reglas simples:
    // "win"  -> no pierde vida
    // "draw" -> SÍ pierde vida (cuenta como derrota)
    // "loss" -> SÍ pierde vida
    // "nulo" -> día nulo manual, NO pierde vida (admin lo marca cuando TODOS empataron)
    const failed = (result === "draw" || result === "loss");
    setSurvivorPicks(prev => ({
      ...prev,
      [username]: {
        ...prev[username],
        [date]: { ...pick, result, failed }
      }
    }));
    try {
      await sb.from("survivor_picks").delete().eq("username", username).eq("date", date);
      const {error: mrErr} = await sb.from("survivor_picks").insert({
        username,
        date,
        team: pick.team,
        failed,
        result,
        match_id: date
      });
      if (mrErr) alert("❌ Error marcando resultado: " + mrErr.message);
    } catch(e) { console.error("Error guardando resultado survivor:", e); }
  }

  const survivors = survivorUsers.filter(u => isUserAlive(u.username));
  const eliminated = survivorUsers.filter(u => !isUserAlive(u.username));

  function fmtD(d) {
    if (!d) return "";
    const [,mo,day] = d.split("-");
    const months=["","ene","feb","mar","abr","may","jun","jul","ago","sep","oct","nov","dic"];
    return `${parseInt(day)} ${months[parseInt(mo)]}`;
  }

  return (
    <div>
      {/* Header */}
      <div style={{background:"linear-gradient(135deg,#1B4F9E,#C41E3A)",border:"none",borderRadius:14,padding:"20px 24px",marginBottom:16}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:32,color:"#F5C518",letterSpacing:4}}>🔥 SURVIVOR</div>
          {isAdmin && (
            <>
            <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",marginTop:8}}>
              <button onClick={() => {
                // Exportar por jornada seleccionada (o jornada actual si no hay selección)
                const jornadaExport = viewJornada || today;
                const datesOfJornada = groupDates.filter(d => getJornadaKeyEarly(d) === jornadaExport);
                const rows = [["Usuario","Nombre","Jornada","¿Envió?","Equipo","Resultado","Falló","Vidas perdidas","Estado"]];
                survivorUsers.forEach(u => {
                  const picks = survivorPicks[u.username] || {};
                  const livesLost = getLivesLost(u.username);
                  const alive = livesLost < 2;
                  // Buscar pick de la jornada exportada
                  const pick = picks[jornadaExport] || datesOfJornada.map(d=>picks[d]).find(Boolean);
                  if (pick) {
                    rows.push([u.username, u.apodo||u.name, jornadaExport, "✅ Enviado",
                      pick.team||"", pick.result||"pendiente", pick.failed?"Sí":"No",
                      livesLost, alive?"VIVO":"ELIMINADO"]);
                  } else {
                    rows.push([u.username, u.apodo||u.name, jornadaExport, "❌ NO envió",
                      "", "", "", livesLost, alive?"VIVO":"ELIMINADO"]);
                  }
                });
                const csv = rows.map(r => r.map(c=>`"${String(c).replace(/"/g,'""')}"`).join(",")).join("\n");
                const blob = new Blob(["\uFEFF"+csv],{type:"text/csv;charset=utf-8;"});
                const a = document.createElement("a");
                a.href = URL.createObjectURL(blob);
                a.download = `Survivor_Jornada_${jornadaExport}.csv`;
                a.click();
                URL.revokeObjectURL(a.href);
              }} style={{padding:"6px 12px",borderRadius:8,border:"1px solid #1B4F9E",background:"rgba(27,79,158,0.08)",color:"#1B4F9E",fontFamily:"inherit",fontSize:12,fontWeight:700,cursor:"pointer"}}>
                📥 Exportar picks Survivor
              </button>
              <span style={{fontSize:13,color:"#6B7A99",fontWeight:700}}>📅 Jornadas habilitadas:</span>
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                {[...new Set(groupDates.map(d=>getJornadaKeyEarly(d)))].map(jk => {
                  const isActive = survivorActiveJornadas.includes(jk);
                  return (
                    <button key={jk} onClick={async()=>{
                      const newActive = isActive
                        ? survivorActiveJornadas.filter(x=>x!==jk)
                        : [...survivorActiveJornadas, jk];
                      setSurvivorActiveJornadas(newActive);
                      await saveConfig("survivorActiveJornadas", newActive.join(","));
                      // Mantener survivorMaxDate como la última jornada activa (para compatibilidad)
                      const lastActive = newActive.sort().slice(-1)[0];
                      if (lastActive) await setSurvivorMaxDate(lastActive);
                    }} style={{padding:"5px 10px",borderRadius:8,border:"1px solid",fontSize:12,fontWeight:700,cursor:"pointer",
                      background:isActive?"#2D8A3E":"transparent",
                      borderColor:isActive?"#2D8A3E":"var(--border)",
                      color:isActive?"#fff":"var(--text)"}}>
                      {isActive?"🔓":"🔒"} {fmtD(jk)}
                    </button>
                  );
                })}
              </div>
              {survivorActiveJornadas.length > 0 && <span style={{fontSize:12,color:"#2D8A3E",fontWeight:700}}>✅ Activas: {survivorActiveJornadas.map(j=>fmtD(j)).join(", ")}</span>}
            </div>
            <div style={{display:"flex",gap:6,alignItems:"center",flexWrap:"wrap",marginTop:8}}>
              <span style={{fontSize:13,color:"#6B7A99",fontWeight:700}}>🔒 Bloquear jornada (clic para activar/desactivar):</span>
              {[...new Set(groupDates.map(d=>getJornadaKeyEarly(d)))].map(jk => {
                const fechasJornada = groupDates.filter(d=>getJornadaKeyEarly(d)===jk);
                const label = fechasJornada.length>1
                  ? fechasJornada.map(d=>d.slice(5)).join("y")
                  : jk.slice(5);
                const isBlocked = survivorBlockedDates.includes(jk);
                return (
                  <button key={jk} onClick={async()=>{
                    const newBlocked = isBlocked
                      ? survivorBlockedDates.filter(x=>x!==jk)
                      : [...survivorBlockedDates, jk];
                    setSurvivorBlockedDates(newBlocked);
                    await saveConfig("survivorBlockedDates", newBlocked.join(","));
                  }} style={{padding:"5px 10px",borderRadius:8,border:"1px solid",fontSize:12,fontWeight:700,cursor:"pointer",
                    background:isBlocked?"#C41E3A":"transparent",
                    borderColor:isBlocked?"#C41E3A":"var(--border)",
                    color:isBlocked?"#fff":"var(--text)"}}>
                    {isBlocked?"🔒":"🔓"} {label}
                  </button>
                );
              })}
            </div>
            </>
          )}
        </div>
        <div style={{fontSize:15,color:"#E8EDF5",marginTop:4,lineHeight:1.7}}>
          Elige 1 equipo por jornada · Solo gana quien <strong>GANA</strong> en 90 minutos · Empate o derrota = pierdes vida<br/>
          <strong>2 vidas</strong> · No repites equipos · Días nulos: si todos los partidos empatan, nadie pierde vida
        </div>
        <div style={{display:"flex",gap:10,marginTop:12,flexWrap:"wrap"}}>
          <div style={{background:"#E8F5E9",border:"1px solid var(--green)",borderRadius:8,padding:"8px 16px",textAlign:"center"}}>
            <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:28,color:"#2D8A3E"}}>{survivors.length}</div>
            <div style={{fontSize:14,color:"#6B7A99"}}>Vivos 🟢</div>
          </div>
          <div style={{background:"#FFEBEE",border:"1px solid var(--red)",borderRadius:8,padding:"8px 16px",textAlign:"center"}}>
            <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:28,color:"#C41E3A"}}>{eliminated.length}</div>
            <div style={{fontSize:14,color:"#6B7A99"}}>Eliminados 💀</div>
          </div>
          <div style={{background:"#FFF8E1",border:"1px solid var(--gold)",borderRadius:8,padding:"8px 16px",flex:1,minWidth:160}}>
            <div style={{fontSize:14,color:"#6B7A99"}}>Premio</div>
            <div style={{fontSize:15,color:"#1B4F9E",fontWeight:700}}>85% Ganador · 5% 2do Puesto · 5% Hogar AMYSER · 5% Admin</div>
          </div>
        </div>
      </div>

      {/* My status — only for non-admin survivor players */}
      {!isAdmin && currentUser.survivorEnabled && (
        <div style={{background:"#FFFFFF",border:`2px solid ${myAlive?"var(--green)":"var(--red)"}`,borderRadius:14,padding:"16px 20px",marginBottom:16}}>
          <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:12}}>
            <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:26,color:myAlive?"var(--green)":"var(--red)"}}>
              {myAlive?"✅ VIVO":"💀 ELIMINADO"}
            </div>
            <div style={{display:"flex",gap:4}}>
              {[0,1].map(i=><span key={i} style={{fontSize:24}}>{i<(2-myLivesLost)?"❤️":"🖤"}</span>)}
            </div>
            <div style={{fontSize:15,color:"#6B7A99"}}>{2-myLivesLost} vida{2-myLivesLost!==1?"s":""} restante{2-myLivesLost!==1?"s":""}</div>
          </div>

          {/* My pick history */}
          {Object.keys(myPicks).length > 0 && (
            <div style={{marginBottom:12}}>
              <div style={{fontSize:14,color:"#6B7A99",marginBottom:6,fontWeight:700,letterSpacing:1,textTransform:"uppercase"}}>Historial de picks</div>
              <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                {Object.entries(myPicks).sort(([a],[b])=>a>b?1:-1).map(([date, pick]) => (
                  <div key={date} style={{
                    padding:"6px 10px",borderRadius:8,fontSize:15,fontWeight:600,
                    background: pick.result==="nulo"?"rgba(107,122,153,0.15)":pick.failed?"rgba(232,64,64,0.15)":pick.result==="win"?"rgba(0,168,107,0.15)":"var(--dark)",
                    border:`1px solid ${pick.result==="nulo"?"#6B7A99":pick.failed?"var(--red)":pick.result==="win"?"var(--green)":"var(--border)"}`
                  }}>
                    <FlagImg team={pick.team} size={15}/> {pick.team}
                    <span style={{marginLeft:6,fontSize:12,color:"#6B7A99"}}>{fmtD(date)}</span>
                    {pick.result==="win" && <span style={{marginLeft:4}}>✅</span>}
                    {pick.result==="draw" && <span style={{marginLeft:4}}>💀 empató</span>}
                    {pick.result==="loss" && <span style={{marginLeft:4}}>💀</span>}
                    {pick.result==="nulo" && <span style={{marginLeft:4,fontSize:12,color:"#6B7A99"}}>🟦 día nulo</span>}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Pick inputs — una por cada jornada activa pendiente */}
          {!myAlive ? null : !canPickToday ? (
            <div style={{background:"rgba(107,122,153,0.1)",border:"1px solid var(--border)",borderRadius:10,padding:"12px 16px",fontSize:14,color:"#6B7A99",fontWeight:700,textAlign:"center"}}>
              📅 No hay jornadas habilitadas en este momento. Pronto podrás enviar tu pick.
            </div>
          ) : (
            <>{allActiveJornadas.map(jornadaKey => {
              // Buscar si ya envió pick para esta jornada específica
              const datesOfJornada = groupDates.filter(d=>getJornadaKeyEarly(d)===jornadaKey);
              const sentPick = myPicks[jornadaKey] || datesOfJornada.map(d=>myPicks[d]).find(Boolean);
              const jornadaMatches = GROUP_MATCHES.filter(m => datesOfJornada.includes(m.date));
              const jornadaTeams = [...new Set(jornadaMatches.flatMap(m=>[m.home,m.away]))];
              const availTeams = jornadaTeams.filter(t => !myUsedTeams.includes(t));

              if (sentPick) {
                // Ya envió — mostrar confirmación + botón re-sincronizar si no está en Supabase
                return (
                  <div key={jornadaKey} style={{background:"rgba(45,138,62,0.08)",border:"1px solid var(--green)",borderRadius:10,padding:"12px 16px"}}>
                    <div style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
                      <span style={{fontSize:14,color:"#2D8A3E",fontWeight:700}}>✅ Pick {fmtD(jornadaKey)} — no se puede cambiar:</span>
                      <FlagImg team={sentPick.team} size={18}/>
                      <span style={{fontWeight:700,fontSize:15}}>{sentPick.team}</span>
                      {sentPick.result
                        ? <span style={{fontSize:14,color:sentPick.result==="win"?"var(--green)":sentPick.result==="nulo"?"#6B7A99":"var(--red)"}}>
                            {sentPick.result==="win"?"✅ Ganó":sentPick.result==="nulo"?"🟦 Día nulo":sentPick.result==="draw"?"💀 Empató":"💀 Perdió"}
                          </span>
                        : <span style={{fontSize:13,color:"#6B7A99"}}>· Pendiente resultado</span>}
                    </div>
                  </div>
                );
              }
              // No envió — mostrar selector para esta jornada
              return (
                <div key={jornadaKey} style={{background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.15)",borderRadius:12,padding:"14px 18px"}}>
                  <div style={{fontSize:14,color:"#6B7A99",marginBottom:8,fontWeight:700}}>
                    🎯 Tu pick · Jornada {fmtD(jornadaKey)}
                  </div>
                  {availTeams.length > 0 ? (
                    <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
                      <select value={selectedTeam} onChange={e=>setSelectedTeam(e.target.value)}
                        style={{padding:"8px 12px",borderRadius:8,border:"1px solid var(--border)",fontFamily:"inherit",fontSize:15,background:"#F8F9FC",color:"#1A1A2E",flex:1,minWidth:180}}>
                        <option value="">-- Elige tu equipo --</option>
                        {availTeams.map(t=><option key={t} value={t}>{t}</option>)}
                      </select>
                      <button className="btn-save" onClick={async()=>{
                        if (!selectedTeam) return;
                        setSaved(false);
                        const pickDate = jornadaKey;
                        setSurvivorPicks(prev=>({...prev,[currentUser.username]:{...(prev[currentUser.username]||{}),[pickDate]:{team:selectedTeam,failed:false,result:null}}}));
                        await sb.from("survivor_picks").delete().eq("username",currentUser.username).eq("date",pickDate);
                        await sb.from("survivor_picks").insert({username:currentUser.username,date:pickDate,team:selectedTeam,failed:false,result:null,match_id:pickDate});
                        setSaved(true);
                        setSelectedTeam("");
                        setTimeout(()=>setSaved(false),2500);
                      }} style={{padding:"10px 20px",background:"var(--gold)",color:"#000",borderRadius:8,border:"none",fontFamily:"inherit",fontSize:15,fontWeight:700,cursor:"pointer"}}>
                        🔥 Confirmar pick
                      </button>
                      {saved && <span style={{color:"#2D8A3E",fontSize:15,fontWeight:700}}>✅ ¡Pick guardado!</span>}
                    </div>
                  ) : (
                    <div style={{fontSize:15,color:"#C41E3A",fontWeight:600}}>⚠️ Ya usaste todos los equipos que juegan esta jornada.</div>
                  )}
                </div>
              );
            })}</>
          )}
          {!myAlive && (
            <div style={{fontSize:16,color:"#C41E3A",fontWeight:700,textAlign:"center",padding:"10px 0"}}>
              💀 Has sido eliminado del Survivor. ¡Mejor suerte la próxima!
            </div>
          )}
        </div>
      )}

      {/* All survivors status table — filtrable por jornada */}
      <div style={{marginBottom:20}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8,marginBottom:10}}>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"#1B4F9E",letterSpacing:2}}>
            👥 Estado Survivor ({survivors.length} vivos / {survivorUsers.length})
          </div>
          {isAdmin && (
            <div style={{display:"flex",gap:6,alignItems:"center"}}>
              <span style={{fontSize:13,color:"#6B7A99",fontWeight:700}}>📅 Ver jornada:</span>
              <select value={viewJornada} onChange={e=>setViewJornada(e.target.value)}
                style={{padding:"6px 10px",borderRadius:8,border:"1px solid var(--border)",fontFamily:"inherit",fontSize:13,background:"#F8F9FC",color:"#1A1A2E"}}>
                <option value="">-- Jornada actual ({fmtD(today)}) --</option>
                {[...new Set(groupDates.map(d=>getJornadaKeyEarly(d)))].map(jk=>(
                  <option key={jk} value={jk}>Jornada {fmtD(jk)}</option>
                ))}
              </select>
            </div>
          )}
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          {survivorUsers.sort((a,b) => {
            const aLives = 2 - getLivesLost(a.username);
            const bLives = 2 - getLivesLost(b.username);
            return bLives - aLives;
          }).map(u => {
            const picks = survivorPicks[u.username] || {};
            const livesLost = getLivesLost(u.username);
            const alive = livesLost < 2;
            // Jornada a mostrar: la seleccionada por admin, o la jornada actual (todayJornadaKey)
            const jornadaToShow = viewJornada || todayJornadaKey;
            const datesOfJornada = groupDates.filter(d=>getJornadaKeyEarly(d)===jornadaToShow);
            const shownPick = picks[jornadaToShow]
              || datesOfJornada.map(d=>picks[d]).find(Boolean)
              || null;
            const usedTeams = Object.values(picks).map(p=>p.team).filter(Boolean);
            const labelSuffix = viewJornada ? `· jornada ${fmtD(viewJornada)}` : "hoy";
            return (
              <div key={u.username} style={{
                display:"flex",alignItems:"center",gap:12,padding:"12px 16px",
                background:"#F8F9FC",borderRadius:12,
                border:`1px solid ${u.username===currentUser.username?"var(--gold)":alive?"var(--border)":"var(--red)"}`,
                opacity:alive?1:0.55
              }}>
                <div style={{width:36,height:36,borderRadius:"50%",background:avatarColor(u.apodo||u.name),
                  display:"flex",alignItems:"center",justifyContent:"center",fontWeight:700,fontSize:15,flexShrink:0}}>
                  {initials(u.apodo||u.name)}
                </div>
                <div style={{flex:1}}>
                  <div style={{fontWeight:600,fontSize:15}}>{u.apodo||u.name}</div>
                  <div style={{fontSize:14,color:"#6B7A99",marginTop:2}}>
                    {shownPick
                      ? <span><FlagImg team={shownPick.team} size={14}/> {shownPick.team} {labelSuffix}
                          {shownPick.result==="win" && <span style={{marginLeft:4,color:"var(--green)"}}>✅</span>}
                          {shownPick.result==="nulo" && <span style={{marginLeft:4,color:"#6B7A99"}}>🟦</span>}
                          {shownPick.failed && <span style={{marginLeft:4,color:"var(--red)"}}>💀</span>}
                        </span>
                      : <span style={{color:"#C41E3A"}}>Sin pick {labelSuffix}</span>}
                    {usedTeams.length > 0 && <span style={{marginLeft:8}}>· Usados: {usedTeams.length} equipos</span>}
                  </div>
                  {Object.keys(picks).length > 0 && (
                    <div style={{display:"flex",flexWrap:"wrap",gap:4,marginTop:4}}>
                      {Object.entries(picks).sort(([a],[b])=>a>b?1:-1).map(([d,p]) => (
                        <span key={d} style={{
                          fontSize:12,padding:"2px 8px",borderRadius:6,fontWeight:600,
                          background: p.result==="nulo"?"rgba(107,122,153,0.1)":p.failed?"rgba(232,64,64,0.12)":p.result==="win"?"rgba(0,168,107,0.12)":"rgba(107,122,153,0.1)",
                          border:`1px solid ${p.result==="nulo"?"#6B7A99":p.failed?"var(--red)":p.result==="win"?"var(--green)":"var(--border)"}`,
                          color: p.failed?"var(--red)":p.result==="win"?"var(--green)":"#1A1A2E"
                        }}>
                          {fmtD(d)}: {p.team==="Sin pick" ? "Sin pick" : <><FlagImg team={p.team} size={12}/> {p.team}</>}
                          {p.result==="win" && " ✅"}
                          {p.result==="nulo" && " 🟦"}
                          {p.failed && " 💀"}
                        </span>
                      ))}
                    </div>
                  )}
                </div>
                <div style={{display:"flex",gap:3}}>
                  {[0,1].map(i=><span key={i} style={{fontSize:20}}>{i<(2-livesLost)?"❤️":"🖤"}</span>)}
                </div>
                <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:16,color:alive?"var(--green)":"var(--red)"}}>
                  {alive?"VIVO":"FUERA"}
                </div>
              </div>
            );
          })}
          {survivorUsers.length === 0 && (
            <div style={{textAlign:"center",padding:"30px",color:"#6B7A99",fontSize:15}}>
              Ningún participante tiene el Survivor activado aún.
            </div>
          )}
        </div>
      </div>

      {/* ADMIN: mark results */}
      {isAdmin && (
        <div>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"#1B4F9E",letterSpacing:2,marginBottom:8}}>
            ⚙️ Admin: Marcar resultados del Survivor
          </div>
          <div style={{marginBottom:12,fontSize:14,color:"#6B7A99"}}>
            ⚠️ Día nulo: si TODOS los partidos de una jornada empatan, nadie pierde vida.
          </div>

          {/* Panel ingreso manual de pick */}
          {(()=>{
            const jornadaParaManual = manualPickDate || viewJornada || todayJornadaKey;
            const teamsForJornada = [...new Set(
              GROUP_MATCHES.filter(m => groupDates.filter(d=>getJornadaKeyEarly(d)===jornadaParaManual).includes(m.date))
              .flatMap(m=>[m.home,m.away])
            )].sort();
            return (
              <div style={{marginBottom:14,background:"rgba(27,79,158,0.06)",border:"1px solid rgba(27,79,158,0.3)",borderRadius:10,padding:"12px 14px"}}>
                <div style={{fontWeight:700,fontSize:14,color:"#1B4F9E",marginBottom:8}}>✍️ Ingresar pick manualmente (para picks que no se guardaron en Supabase)</div>
                <div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"center"}}>
                  <select value={manualPickDate || viewJornada || todayJornadaKey} onChange={e=>setManualPickDate(e.target.value)}
                    style={{padding:"6px 10px",borderRadius:8,border:"1px solid var(--border)",fontFamily:"inherit",fontSize:13,background:"#fff"}}>
                    <option value="">-- Jornada --</option>
                    {[...new Set(groupDates.map(d=>getJornadaKeyEarly(d)))].map(jk=>(
                      <option key={jk} value={jk}>{fmtD(jk)}</option>
                    ))}
                  </select>
                  <select value={manualUser} onChange={e=>setManualUser(e.target.value)}
                    style={{padding:"6px 10px",borderRadius:8,border:"1px solid var(--border)",fontFamily:"inherit",fontSize:13,background:"#fff",minWidth:140}}>
                    <option value="">-- Jugador --</option>
                    {survivorUsers.map(u=><option key={u.username} value={u.username}>{u.apodo||u.name}</option>)}
                  </select>
                  <select value={manualTeam} onChange={e=>setManualTeam(e.target.value)}
                    style={{padding:"6px 10px",borderRadius:8,border:"1px solid var(--border)",fontFamily:"inherit",fontSize:13,background:"#fff",minWidth:140}}>
                    <option value="">-- Equipo --</option>
                    {teamsForJornada.map(t=><option key={t} value={t}>{t}</option>)}
                  </select>
                  <button disabled={!manualUser||!manualTeam||!jornadaParaManual} onClick={async()=>{
                    // Borrar pick previo si existe, luego insertar
                  await sb.from("survivor_picks").delete()
                    .eq("username",manualUser).eq("date",jornadaParaManual);
                  const {error} = await sb.from("survivor_picks").insert({
                    username:manualUser, date:jornadaParaManual, team:manualTeam,
                    failed:false, result:null, match_id:jornadaParaManual
                  });
                    if (!error) {
                      setSurvivorPicks(prev=>({...prev,[manualUser]:{...(prev[manualUser]||{}),[jornadaParaManual]:{team:manualTeam,failed:false,result:null}}}));
                      setManualMsg(`✅ Pick de ${manualTeam} guardado para ${manualUser}`);
                      setManualUser(""); setManualTeam("");
                    } else {
                      setManualMsg("❌ Error: "+error.message);
                    }
                    setTimeout(()=>setManualMsg(""),4000);
                  }} style={{padding:"6px 14px",borderRadius:8,border:"1px solid #1B4F9E",
                    background:(manualUser&&manualTeam&&jornadaParaManual)?"rgba(27,79,158,0.1)":"#eee",
                    color:(manualUser&&manualTeam&&jornadaParaManual)?"#1B4F9E":"#aaa",
                    fontFamily:"inherit",fontSize:13,fontWeight:700,cursor:"pointer"}}>
                    💾 Guardar pick
                  </button>
                  {manualMsg && <span style={{fontSize:13,fontWeight:700,color:manualMsg.startsWith("✅")?"#2D8A3E":"#C41E3A"}}>{manualMsg}</span>}
                </div>
              </div>
            );
          })()}

          <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:14}}>
            <button onClick={()=>checkMissingPicks(viewJornada || todayJornadaKey)} style={{padding:"8px 16px",borderRadius:8,
              border:"2px solid #C41E3A",background:"rgba(196,30,58,0.08)",color:"#C41E3A",
              cursor:"pointer",fontFamily:"inherit",fontSize:14,fontWeight:700}}>
              🔍 Verificar picks faltantes de {fmtD(viewJornada || todayJornadaKey)} (quitar vida)
            </button>
            <button onClick={async()=>{
              const jornadaRevert = viewJornada || todayJornadaKey;
              if (!window.confirm(`¿Revertir eliminaciones automáticas de ${jornadaRevert}? Esto borrará todos los registros "Sin pick" de esa jornada y devolverá las vidas.`)) return;
              const {error} = await sb.from("survivor_picks")
                .delete()
                .eq("date", jornadaRevert)
                .eq("result","nopick");
              if (!error) {
                setSurvivorPicks(prev => {
                  const np = {...prev};
                  Object.keys(np).forEach(u => {
                    if (np[u]?.[jornadaRevert]?.result === "nopick") {
                      const upd = {...np[u]};
                      delete upd[jornadaRevert];
                      np[u] = upd;
                    }
                  });
                  return np;
                });
                alert("✅ Eliminaciones revertidas para " + jornadaRevert);
              } else {
                alert("❌ Error: " + error.message);
              }
            }} style={{padding:"8px 16px",borderRadius:8,
              border:"2px solid #2D8A3E",background:"rgba(45,138,62,0.08)",color:"#2D8A3E",
              cursor:"pointer",fontFamily:"inherit",fontSize:14,fontWeight:700}}>
              ↩️ Revertir eliminaciones de {fmtD(viewJornada || todayJornadaKey)}
            </button>
          </div>
          {groupDates.filter(date => {
            // Si hay jornada seleccionada, mostrar solo esa jornada
            if (viewJornada && getJornadaKeyEarly(date) !== viewJornada) return false;
            return survivorUsers.some(u => survivorPicks[u.username]?.[date]);
          }).map(date => (
            <div key={date} style={{marginBottom:14,background:"#F8F9FC",borderRadius:12,padding:"14px 16px",border:"1px solid var(--border)"}}>
              <div style={{fontWeight:700,fontSize:15,marginBottom:10,color:"#1B4F9E"}}>
                📅 {fmtD(date)}
              </div>
              {survivorUsers.filter(u => survivorPicks[u.username]?.[date]).map(u => {
                const pick = survivorPicks[u.username][date];
                return (
                  <div key={u.username} style={{display:"flex",alignItems:"center",gap:10,marginBottom:8,flexWrap:"wrap",padding:"8px 10px",background:"#FFFFFF",borderRadius:8}}>
                    <span style={{fontSize:15,fontWeight:700,minWidth:120}}>{u.apodo||u.name}</span>
                    <span style={{fontSize:15,color:"#6B7A99",display:"flex",alignItems:"center",gap:4}}>
                      <FlagImg team={pick.team} size={16}/> {pick.team}
                    </span>
                    <div style={{display:"flex",gap:6,marginLeft:"auto",flexWrap:"wrap"}}>
                      {[
                        {r:"win", label:"✅ Ganó", color:"#2D8A3E"},
                        {r:"draw", label:"➖ Empató", color:"#1B4F9E"},
                        {r:"loss", label:"❌ Perdió", color:"#C41E3A"},
                        {r:"nulo", label:"🟦 Día nulo", color:"#6B7A99"},
                      ].map(({r,label,color}) => (
                        <button key={r} onClick={()=>markResult(u.username, date, r)} style={{
                          padding:"5px 10px",borderRadius:6,border:`1px solid ${color}`,
                          fontFamily:"inherit",fontSize:14,fontWeight:700,cursor:"pointer",
                          background:pick.result===r?color:"transparent",
                          color:pick.result===r?"#fff":color
                        }}>{label}</button>
                      ))}
                    </div>
                    {pick.failed && <span style={{fontSize:14,color:"#C41E3A",fontWeight:700}}>💀 -1 vida</span>}
                    {pick.result==="win" && <span style={{fontSize:14,color:"#2D8A3E",fontWeight:700}}>✅ +0 vidas</span>}
                    {pick.result==="nulo" && <span style={{fontSize:14,color:"#6B7A99",fontWeight:700}}>🟦 Día nulo · +0 vidas</span>}
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ============================================================
// BOLSA TAB
// ============================================================
function BolsaTab({users, bolsa, setBolsa, isAdmin}) {
  const participants = users.filter(u => !u.isAdmin);
  const valorBase = bolsa.valorBase || 50000;
  const valorSurvivor = 200000;
  const pagos = bolsa.pagos || {};

  const pagaron = participants.filter(u => pagos[u.username]);
  // Tabla de tarifas correcta:
  // RePoLLo antes 16 mayo: $800.000 | después: $900.000
  // NueVón  antes 16 mayo: $900.000 | después: $1.000.000
  // + Survivor: $200.000 adicionales (independiente)
  function getValorRepolla(u) {
    return u.tipo === "repollo"
      ? (u.fechaEspecial ? 900000 : 800000)
      : (u.fechaEspecial ? 1000000 : 900000);
  }
  function getValorTotal(u) {
    return getValorRepolla(u) + (u.survivorEnabled && u.pagoSurvivor ? 200000 : 0);
  }
  const survivorJugadores = participants.filter(u => u.survivorEnabled && u.pagoSurvivor && pagos[u.username]);
  const totalRePoLLa = pagaron.reduce((sum, u) => {
    const p = pagos[u.username];
    return sum + (p?.valorRepolla || 0);
  }, 0);
  const totalSurvivorReal = survivorJugadores.reduce((sum, u) => {
    const p = pagos[u.username];
    return sum + (p?.valorSurvivor || 0);
  }, 0);
  const totalGeneralReal = totalRePoLLa + totalSurvivorReal;
  const totalGeneral = totalGeneralReal;

  // Prize distribution RePoLLa
  // Distribution: 48/25/15 + 3% sorpresas + 5% AMYSER + 4% Admin

  function fmt(n) {
    return "$" + Math.round(n).toLocaleString("es-CO");
  }

  async function togglePago(username) {
    if (!isAdmin) return;
    const nuevoEstado = !bolsa.pagos?.[username];
    setBolsa(prev => ({
      ...prev,
      pagos: { ...(prev.pagos||{}), [username]: nuevoEstado }
    }));
    try {
      await sb.from("pagos").upsert({
        username,
        pago_repolla: nuevoEstado,
        pago_survivor: nuevoEstado
      }, {onConflict:"username"});
    } catch(e) { console.error("Error guardando pago:", e); }
  }

  return (
    <div>
      {/* Hero bolsa */}
      <div style={{background:"linear-gradient(135deg,#1B4F9E,#2D8A3E)",border:"1px solid #2d8a3e",borderRadius:16,padding:"24px",marginBottom:20,textAlign:"center"}}>
        <div style={{fontSize:24,color:"#FFFFFF",marginBottom:4,letterSpacing:2,textTransform:"uppercase",fontWeight:900}}>💰 Bolsa Total</div>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:56,color:"#F5C518",letterSpacing:4,lineHeight:1}}>
          {fmt(totalGeneral)}
        </div>
        <div style={{fontSize:18,color:"#FFFFFF",fontWeight:700,marginTop:8}}>
          {pagaron.length} participantes pagaron · {survivorJugadores.length} en Survivor
        </div>
        <div style={{display:"flex",gap:10,justifyContent:"center",marginTop:16,flexWrap:"wrap"}}>
          <div style={{background:"#FFF8E1",border:"1px solid var(--gold)",borderRadius:10,padding:"10px 16px"}}>
            <div style={{fontSize:16,color:"#1A1A2E",fontWeight:900}}>RePoLLa</div>
            <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:28,color:"#1B4F9E"}}>{fmt(totalRePoLLa)}</div>
          </div>
          <div style={{background:"rgba(232,64,64,0.12)",border:"1px solid var(--red)",borderRadius:10,padding:"10px 16px"}}>
            <div style={{fontSize:16,color:"#FFFFFF",fontWeight:900}}>🔥 Survivor</div>
            <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:28,color:"#FFFFFF"}}>{fmt(totalSurvivorReal)}</div>
          </div>
        </div>
      </div>

      {/* Prize distribution RePoLLa */}
      <div style={{background:"#FFFFFF",border:"1px solid var(--border)",borderRadius:14,padding:"18px 20px",marginBottom:16}}>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"#1B4F9E",letterSpacing:2,marginBottom:14}}>🥬 Distribución Premio RePoLLa</div>
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {[
            {label:"🥇 1er Lugar (48%)", val:totalRePoLLa*0.48, color:"#FFD700"},
            {label:"🥈 2do Lugar (25%)", val:totalRePoLLa*0.25, color:"#C0C0C0"},
            {label:"🥉 3er Lugar (15%)", val:totalRePoLLa*0.15, color:"#CD7F32"},
            {label:"🏆 Premios Sorpresa (3%)", val:totalRePoLLa*0.03, color:"#1B4F9E"},
            {label:"❤️ Hogar AMYSER (5%)", val:totalRePoLLa*0.05, color:"#C41E3A"},
            {label:"⚙️ Administración (4%)", val:totalRePoLLa*0.04, color:"#6B7A99"},
          ].map((row,i) => (
            <div key={i} style={{display:"flex",alignItems:"center",justifyContent:"space-between",
              padding:"10px 14px",background:"#F8F9FC",borderRadius:10,border:"1px solid var(--border)"}}>
              <div style={{fontSize:16,fontWeight:700,color:"#1A1A2E"}}>{row.label}</div>
              <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:26,color:row.color}}>{fmt(row.val)}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Prize distribution Survivor */}
      <div style={{background:"#FFFFFF",border:"2px solid #C41E3A",borderRadius:14,padding:"18px 20px",marginBottom:20}}>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"#C41E3A",letterSpacing:2,marginBottom:14}}>🔥 Distribución Premio Survivor</div>
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {[
            {label:"🥇 Ganador (85%)", val:totalSurvivorReal*0.85, color:"#FFD700"},
            {label:"🥈 2do Puesto (5%)", val:totalSurvivorReal*0.05, color:"#C0C0C0"},
            {label:"❤️ Hogar AMYSER (5%)", val:totalSurvivorReal*0.05, color:"#C41E3A"},
            {label:"⚙️ Administración (5%)", val:totalSurvivorReal*0.05, color:"#6B7A99"},
          ].map((row,i) => (
            <div key={i} style={{display:"flex",alignItems:"center",justifyContent:"space-between",
              padding:"10px 14px",background:"rgba(196,30,58,0.04)",borderRadius:10,border:"1px solid rgba(196,30,58,0.15)"}}>
              <div style={{fontSize:16,fontWeight:700,color:"#1A1A2E"}}>{row.label}</div>
              <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:26,color:row.color}}>{fmt(row.val)}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Surprise prizes */}
      <div style={{background:"#FFFFFF",border:"1px solid var(--border)",borderRadius:14,padding:"18px 20px",marginBottom:20}}>
        <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"#1B4F9E",letterSpacing:2,marginBottom:14}}>🎁 Premios Sorpresa</div>
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {[
            {label:"🧱 'The Wall' Award", desc:"Mayor número de empates acertados en todo el Mundial", prize:"1% de la bolsa"},
            {label:"📰 'Fake News Trophy'", desc:"Más veces que falle por exactamente un gol de diferencia", prize:"1% de la bolsa"},
            {label:"🥬 RePoLLo Supremo", desc:"Mayor puntaje únicamente en fase de grupos", prize:"1% de la bolsa"},
            {label:"⚽ La Pena Máxima", desc:"Acierta el número total de penales en el Mundial (solo dentro de partidos, NO penales de definición)", prize:"Bono $300.000 La Nacional Carnicería"},
          ].map((p,i)=>(
            <div key={i} style={{padding:"10px 14px",background:"#F8F9FC",borderRadius:10,border:"1px solid var(--border)"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:6}}>
                <div>
                  <div style={{fontSize:15,fontWeight:700,color:"#1A1A2E"}}>{p.label}</div>
                  <div style={{fontSize:14,color:"#6B7A99",marginTop:2}}>{p.desc}</div>
                </div>
                <div style={{fontSize:15,fontWeight:700,color:"#1B4F9E",whiteSpace:"nowrap"}}>{p.prize}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* AMYSER */}
      <div style={{background:"linear-gradient(135deg,#E3EFFF,#E8F5E9)",border:"1px solid #1B4F9E",borderRadius:14,padding:"16px 20px",marginBottom:20,display:"flex",alignItems:"center",gap:14}}>
        <div style={{fontSize:32}}>❤️</div>
        <div>
          <div style={{fontWeight:700,fontSize:16,color:"#93c5fd"}}>Hogar AMYSER</div>
          <div style={{fontSize:15,color:"#6B7A99",marginTop:2}}>Hogar para mujeres adultas mayores en Bogotá</div>
          <div style={{fontSize:14,color:"#6B7A99"}}>📍 Calle 145 No. 9-71 · @hogaramyser</div>
        </div>
        <div style={{marginLeft:"auto",textAlign:"right"}}>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:26,color:"#3B82F6"}}>{fmt(totalGeneral*0.05)}</div>
          <div style={{fontSize:14,color:"#6B7A99"}}>5% de la bolsa</div>
        </div>
      </div>
      <div>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10,flexWrap:"wrap",gap:8}}>
          <div style={{fontFamily:"'Bebas Neue',cursive",fontSize:22,color:"#1B4F9E",letterSpacing:2}}>
            👥 Estado de Pagos ({pagaron.length}/{participants.length})
          </div>
          {isAdmin && (
            <button onClick={()=>{
              const rows = [["Nombre","Apodo","Username","Tipo","RePoLLa","Survivor","Total"]];
              participants.forEach(u => {
                const p = pagos[u.username];
                const rep = p?.valorRepolla || 0;
                const sur = p?.valorSurvivor || 0;
                rows.push([u.name, u.apodo||"", u.username, u.tipo, rep, sur, rep+sur]);
              });
              const csv = rows.map(r=>r.join(";")).join("\n");
              const blob = new Blob(["\uFEFF"+csv], {type:"text/csv;charset=utf-8;"});
              const a = document.createElement("a");
              a.href = URL.createObjectURL(blob);
              a.download = "pagos_repolla2026.csv";
              a.click();
            }} style={{padding:"7px 14px",borderRadius:8,border:"1px solid #2D8A3E",background:"rgba(45,138,62,0.08)",color:"#2D8A3E",cursor:"pointer",fontFamily:"inherit",fontSize:14,fontWeight:700}}>
              📥 Exportar Excel
            </button>
          )}
        </div>
        {isAdmin && <div style={{fontSize:15,color:"#6B7A99",marginBottom:10}}>Como admin puedes marcar quién ha pagado tocando su nombre.</div>}
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {participants.map(u => {
            const paid = pagos[u.username];
            const valorCalculado = getValorTotal(u);
            const valorManual = bolsa.pagosManual?.[u.username];
            const valorFinal = valorManual !== undefined ? valorManual : valorCalculado;
            return (
              <div key={u.username}
                style={{display:"flex",alignItems:"center",gap:12,padding:"12px 16px",
                  background: paid?"#E8F5E9":"#FFFFFF",
                  border:`2px solid ${paid?"#2D8A3E":"#E0E6F0"}`,
                  borderRadius:12, transition:"all 0.2s",
                  boxShadow:"0 2px 6px rgba(0,0,0,0.04)"}}>
                <div style={{width:36,height:36,borderRadius:"50%",background:avatarColor(u.apodo||u.name),
                  display:"flex",alignItems:"center",justifyContent:"center",fontWeight:700,fontSize:15,flexShrink:0}}>
                  {initials(u.apodo||u.name)}
                </div>
                <div style={{flex:1}}>
                  <div style={{fontWeight:600,fontSize:15,color:"#1A1A2E"}}>{u.apodo||u.name}</div>
                  <div style={{fontSize:13,color:"#6B7A99",marginTop:2}}>
                    {u.tipo==="repollo"?"🥬 RePoLLo":"🆕 NueVón"}
                    {u.survivorEnabled?" · 🔥 Survivor":""}
                    {""}
                  </div>
                </div>
                <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:6}}>
                  <div style={{display:"flex",gap:10,alignItems:"center"}}>
                    <div style={{textAlign:"right"}}>
                      <div style={{fontSize:11,color:"#6B7A99",marginBottom:1}}>🥬 RePoLLa</div>
                      {isAdmin ? (
                        <input type="number"
                          defaultValue={pagos[u.username]?.valorRepolla || getValorRepolla(u)}
                          onBlur={async e => {
                            const val = parseInt(e.target.value)||0;
                            await sb.from("pagos").upsert({username:u.username, valor_repolla:val},{onConflict:"username"});
                            setBolsa(prev => ({...prev, pagos:{...prev.pagos, [u.username]:{...prev.pagos[u.username], valorRepolla:val}}}));
                          }}
                          style={{width:90,fontSize:13,fontWeight:700,color:"#1B4F9E",
                            border:"1px solid #E0E6F0",borderRadius:6,padding:"2px 4px",
                            textAlign:"right",background:"#F8F9FC"}} />
                      ) : (
                        <div style={{fontSize:13,color:"#1B4F9E",fontWeight:700}}>
                          ${(pagos[u.username]?.valorRepolla || getValorRepolla(u)).toLocaleString("es-CO")}
                        </div>
                      )}
                    </div>
                    {u.survivorEnabled && (
                      <div style={{textAlign:"right",borderLeft:"1px solid #E0E6F0",paddingLeft:10}}>
                        <div style={{fontSize:11,color:"#6B7A99",marginBottom:1}}>🔥 Survivor</div>
                        {isAdmin ? (
                          <input type="number"
                            defaultValue={pagos[u.username]?.valorSurvivor||0}
                            onBlur={async e => {
                              const val = parseInt(e.target.value)||0;
                              await sb.from("pagos").upsert({username:u.username, valor_survivor:val},{onConflict:"username"});
                              setBolsa(prev => ({...prev, pagos:{...prev.pagos, [u.username]:{...prev.pagos[u.username], valorSurvivor:val}}}));
                            }}
                            style={{width:80,fontSize:13,fontWeight:700,color:"#C41E3A",
                              border:"1px solid rgba(196,30,58,0.3)",borderRadius:6,padding:"2px 4px",
                              textAlign:"right",background:"rgba(196,30,58,0.05)"}} />
                        ) : (
                        <div style={{fontSize:13,color:"#C41E3A",fontWeight:700}}>
                          ${(pagos[u.username]?.valorSurvivor||0).toLocaleString("es-CO")}
                        </div>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
          {participants.length === 0 && (
            <div style={{textAlign:"center",padding:"40px",color:"#6B7A99",fontSize:15}}>
              Aún no hay participantes registrados.
            </div>
          )}
        </div>
      </div>
    <div style={{textAlign:"center",padding:"8px",fontSize:13,color:"#B0B8CC",
        borderTop:"1px solid #E0E6F0",background:"#F8F9FC",letterSpacing:0.5}}>
        Desarrollado por <strong style={{color:"#1B4F9E"}}>JuliethDueñas/repolla2026</strong>
      </div>
    </div>
  );
}

// ============================================================
// CHANGE PASSWORD SCREEN
// ============================================================
function ChangePasswordScreen({currentUser, changePassword}) {
  const [pass1, setPass1] = React.useState("");
  const [pass2, setPass2] = React.useState("");
  const [error, setError] = React.useState("");
  const [done, setDone] = React.useState(false);

  function handleChange() {
    if (pass1.length < 6) { setError("La contraseña debe tener al menos 6 caracteres"); return; }
    if (pass1 !== pass2) { setError("Las contraseñas no coinciden"); return; }
    if (pass1 === "Repolla2026") { setError("Debes elegir una contraseña diferente a la inicial"); return; }
    changePassword(currentUser.username, pass1);
    setDone(true);
  }

  return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",
      background:"linear-gradient(135deg,#1B4F9E,#2D8A3E)",padding:20}}>
      <div style={{background:"#fff",borderRadius:20,padding:"40px 36px",width:380,
        boxShadow:"0 20px 60px rgba(0,0,0,0.2)"}}>
        <div style={{textAlign:"center",marginBottom:24}}>
          <div style={{fontSize:48,marginBottom:8}}>🔐</div>
          <div style={{fontFamily:"'Montserrat',sans-serif",fontWeight:900,fontSize:24,
            color:"#1B4F9E",marginBottom:6}}>Cambia tu contraseña</div>
          <div style={{fontSize:15,color:"#6B7A99"}}>
            Hola <strong>{currentUser.apodo||currentUser.name}</strong>, es tu primer ingreso.<br/>
            Por seguridad debes crear una contraseña personal.
          </div>
        </div>
        {!done ? (
          <>
            <div className="field">
              <label>Nueva contraseña</label>
              <input type="password" value={pass1} onChange={e=>setPass1(e.target.value)}
                placeholder="Mínimo 6 caracteres" />
            </div>
            <div className="field">
              <label>Confirmar contraseña</label>
              <input type="password" value={pass2} onChange={e=>setPass2(e.target.value)}
                placeholder="Repite tu contraseña"
                onKeyDown={e=>e.key==="Enter"&&handleChange()} />
            </div>
            {error && <div style={{color:"#C41E3A",fontSize:15,marginBottom:12,fontWeight:600}}>{error}</div>}
            <button className="btn-primary" onClick={handleChange}>Guardar contraseña</button>
          </>
        ) : (
          <div style={{textAlign:"center",padding:"20px 0"}}>
            <div style={{fontSize:48,marginBottom:12}}>✅</div>
            <div style={{fontSize:18,fontWeight:700,color:"#2D8A3E",marginBottom:8}}>¡Contraseña guardada!</div>
            <div style={{fontSize:15,color:"#6B7A99",marginBottom:20}}>Ya puedes ingresar a la app.</div>
            <button className="btn-primary" onClick={()=>window.location.reload()}>Entrar a RePoLLa</button>
          </div>
        )}
      </div>
    </div>
  );
}

